import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        System.out.println(minStepsToOne(N));
    }
    public static int minStepsToOne(int N) {
        Queue<Integer> queue = new LinkedList<>();
        Set<Integer> visited = new HashSet<>();
        queue.offer(N);
        visited.add(N);
        int steps = 0;
        while (!queue.isEmpty()) {
            int size = queue.size();
            for (int i = 0; i < size; i++) {
                int current = queue.poll();
                if (current == 1) return steps;
                for (int divisor : getDivisors(current)) {
                    int nextNumber = current - divisor;
                    if (nextNumber >= 1 && !visited.contains(nextNumber)) {
                        visited.add(nextNumber);
                        queue.offer(nextNumber);
                    }
                }
            }
            steps++;
        }
        return -1; // This should not happen for the given constraints
    }
    public static List<Integer> getDivisors(int n) {
        List<Integer> divisors = new ArrayList<>();
        for (int i = 1; i <= n; i++) {
            if (n % i == 0) divisors.add(i);
        }
        return divisors;
    }
}

