import java.util.*;
public class RestaurantReservation {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int[] tables = new int[n];
        for (int i = 0; i < n; i++) {
            tables[i] = sc.nextInt();
        }
        sc.nextLine();
        String command;
        while (sc.hasNextLine()) {
            command = sc.nextLine();
            String[] parts = command.split(" ");
            String action = parts[0];
            int index = Integer.parseInt(parts[1]);
            if (action.equals("ADD")) {
                System.out.println(addReservation(tables, index));
            } else if (action.equals("REMOVE")) {
                System.out.println(removeReservation(tables, index));
            } else if (action.equals("CHECK")) {
                System.out.println(checkAvailability(tables, index));
            }
        }
    }
    private static int addReservation(int[] tables, int index) {
        if (tables[index] == 0) {
            tables[index] = 1;
            return index;
        }
        return -1;
    }
    private static int removeReservation(int[] tables, int index) {
        if (tables[index] == 1) {
            tables[index] = 0;
            return index;
        }
        return -1;
    }
    private static String checkAvailability(int[] tables, int index) {
        List<Integer> available = new ArrayList<>();
        if (index > 0 && tables[index - 1] == 0) available.add(index - 1);
        if (index < tables.length - 1 && tables[index + 1] == 0) available.add(index + 1);
        return available.isEmpty() ? "" : available.toString().replaceAll("[\[\],]", "");
    }
}

