using namespace std;
int main() {
    int N, M;
    cin >> N >> M;
    vector<vector<pair<int, int>>> graph(N + 1);
    for (int i = 0; i < M; i++) {
        int u, v, cost;
        cin >> u >> v >> cost;
        graph[u].emplace_back(v, cost);
    }
    int start;
    cin >> start;
    set<int> targets;
    int target_count;
    cin >> target_count;
    for (int i = 0; i < target_count; i++) {
        int target;
        cin >> target;
        targets.insert(target);
    }
    vector<int> dist(N + 1, INT_MAX);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;
    dist[start] = 0;
    pq.emplace(0, start);
    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();
        if (d > dist[u]) continue;
        for (auto [v, cost] : graph[u]) {
            if (dist[u] + cost < dist[v]) {
                dist[v] = dist[u] + cost;
                pq.emplace(dist[v], v);
            }
        }
    }
    vector<int> reachable;
    for (int target : targets) {
        if (dist[target] < INT_MAX) {
            reachable.push_back(target);
        }
    }
    sort(reachable.begin(), reachable.end());
    cout << reachable.size() << endl;
    for (int loc : reachable) {
        cout << loc << endl;
    }
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        Map<Integer, List<int[]>> graph = new HashMap<>();
        for (int i = 0; i < M; i++) {
            int u = scanner.nextInt();
            int v = scanner.nextInt();
            int cost = scanner.nextInt();
            graph.putIfAbsent(u, new ArrayList<>());
            graph.get(u).add(new int[]{v, cost});
        }
        int start = scanner.nextInt();
        List<Integer> destinations = new ArrayList<>();
        while (scanner.hasNextInt()) {
            destinations.add(scanner.nextInt());
        }
        Set<Integer> reachable = new TreeSet<>();
        dijkstra(start, graph, reachable);
        reachable.retainAll(destinations);
        System.out.println(reachable.size());
    }
    private static void dijkstra(int start, Map<Integer, List<int[]>> graph, Set<Integer> reachable) {
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[1]));
        pq.offer(new int[]{start, 0});
        Set<Integer> visited = new HashSet<>();
        while (!pq.isEmpty()) {
            int[] current = pq.poll();
            int node = current[0];
            int cost = current[1];
            if (visited.contains(node)) continue;
            visited.add(node);
            reachable.add(node);
            if (!graph.containsKey(node)) continue;
            for (int[] edge : graph.get(node)) {
                int neighbor = edge[0];
                int newCost = cost + edge[1];
                if (!visited.contains(neighbor)) {
                    pq.offer(new int[]{neighbor, newCost});
                }
            }
        }
    }
}

