} Post;
typedef struct Node {
    int user_id;
    struct Node *next;
} Node;
Node *followers[MAX_USERS];
Post posts[MAX_POSTS];
bool seen_posts[MAX_POSTS];
int post_count = 0;
void add_follower(int u, int v) {
    Node *new_node = (Node *)malloc(sizeof(Node));
    new_node->user_id = v;
    new_node->next = followers[u];
    followers[u] = new_node;
}
int compare(const void *a, const void *b) {
    Post *post_a = (Post *)a;
    Post *post_b = (Post *)b;
    return strcmp(post_a->timestamp, post_b->timestamp);
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    for (int i = 0; i < N; i++) {
        followers[i] = NULL;
    }
    for (int i = 0; i < M; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        add_follower(u - 1, v - 1);
    }
    scanf("%d", &post_count);
    for (int i = 0; i < post_count; i++) {
        int user_id;
        char content[256];
        char timestamp[20];
        scanf("%d %s %[^
]s %s", &user_id, content, timestamp);
        posts[i].user_id = user_id - 1;
        strcpy(posts[i].content, content);
        strcpy(posts[i].timestamp, timestamp);
        seen_posts[i] = false;
    }
    int idx = 0;
    for (int i = 0; i < N; i++) {
        Node *current = followers[i];
        while (current != NULL) {
            for (int j = 0; j < post_count; j++) {
                if (posts[j].user_id == current->user_id && !seen_posts[j]) {
                    seen_posts[j] = true;
                    posts[idx++] = posts[j];
                }
            }
            current = current->next;
        }
    }
    qsort(posts, idx, sizeof(Post), compare);
    for (int i = 0; i < idx; i++) {
        printf("%s %s
", posts[i].content, posts[i].timestamp);
    }
    return 0;
}

