        }
    }
    int initialHP, initialMoney;
    scanf("%d %d", &initialHP, &initialMoney);
    int healthItems[MAX][2], moneyItems[MAX][2];
    int healthItemCount = 0, moneyItemCount = 0;
    while (scanf("(%d, %d)", &healthItems[healthItemCount][0], &healthItems[healthItemCount][1]) == 2) {
        healthItemCount++;
    }
    while (scanf("(%d, %d)", &moneyItems[moneyItemCount][0], &moneyItems[moneyItemCount][1]) == 2) {
        moneyItemCount++;
    }
    // BFS initialization
    int queue[MAX * MAX][3]; // x, y, distance
    int front = 0, rear = 0;
    queue[rear][0] = 0; queue[rear][1] = 0; queue[rear][2] = 0; rear++;
    int visited[MAX][MAX];
    memset(visited, 0, sizeof(visited));
    visited[0][0] = 1;
    int finalHP = initialHP, finalMoney = initialMoney;
    int found = 0;
    while (front < rear) {
        int x = queue[front][0];
        int y = queue[front][1];
        int dist = queue[front][2];
        front++;
        // Check if reached goal
        if (x == N - 1 && y == M - 1) {
            printf("%d %d %d
", dist, finalHP, finalMoney);
            found = 1;
            break;
        }
        // Move to adjacent cells
        int directions[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
