                visited[newX][newY] = 1;
                queue[rear][0] = newX;
                queue[rear][1] = newY;
                queue[rear][2] = dist + 1;
                rear++;
            }
        }
        // Check for health items
        for (int i = 0; i < healthItemCount; i++) {
            if (x == healthItems[i][0] && y == healthItems[i][1]) {
                if (finalHP < 20) finalHP++;
            }
