            for (auto [dx, dy] : directions) {
                int newX = x + dx;
                int newY = y + dy;
                if (newX >= 0 && newX < M && newY >= 0 && newY < N && !visited[newX][newY] && abs(grid[newX][newY] - grid[startX][startY]) > T) {
                    visited[newX][newY] = true;
                    q.push({newX, newY});
                }
            }
        }
        maxDistance++;  // Increment distance for each level of BFS
    }
    cout << count << " " << maxDistance - 1;
    return 0;
}

