        if (current == target) return true;
        visited[current] = true;
        for (int neighbor : graph.getOrDefault(current, new ArrayList<>())) {
            if (!visited[neighbor] && dfs(graph, neighbor, target, visited)) {
                return true;
            }
        }
        return false;
    }
}

