#include <string.h>
#define MAX 100
typedef struct {
    int x, y;
} Point;
int grid[MAX][MAX];
int visited[MAX][MAX];
int directions[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
int bfs(int startX, int startY, int N, int M) {
    Point queue[MAX * MAX];
    int front = 0, rear = 0;
    queue[rear++] = (Point){startX, startY};
    visited[startX][startY] = 1;
    int distance = 1;
    while (front < rear) {
        int size = rear - front;
        for (int i = 0; i < size; i++) {
            Point current = queue[front++];
            if (grid[current.x][current.y] == 2) {
                return distance;
            }
            for (int j = 0; j < 4; j++) {
                int newX = current.x + directions[j][0];
                int newY = current.y + directions[j][1];
                if (newX >= 0 && newY >= 0 && newX < N && newY < M &&
                    !visited[newX][newY] && grid[newX][newY] != 1) {
                    visited[newX][newY] = 1;
                    queue[rear++] = (Point){newX, newY};
                }
            }
        }
        distance++;
    }
    return -1;
