import java.util.LinkedList;
import java.util.Queue;
public class Main {
    public static void main(String[] args) {
        java.util.Scanner scanner = new java.util.Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        scanner.nextLine();
        char[][] grid = new char[N][M];
        int startX = -1, startY = -1;
        for (int i = 0; i < N; i++) {
            String line = scanner.nextLine();
            for (int j = 0; j < M; j++) {
                grid[i][j] = line.charAt(j);
                if (grid[i][j] == 'S') {
                    startX = i;
                    startY = j;
                }
            }
        }
        int result = bfs(grid, startX, startY);
        System.out.println(result);
    }
    private static int bfs(char[][] grid, int startX, int startY) {
        int N = grid.length;
        int M = grid[0].length;
        boolean[][] visited = new boolean[N][M];
        int[][] directions = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
        Queue<int[]> queue = new LinkedList<>();
        queue.offer(new int[]{startX, startY, 1}); // x, y, distance
        visited[startX][startY] = true;
        while (!queue.isEmpty()) {
            int[] current = queue.poll();
            int x = current[0];
            int y = current[1];
            int distance = current[2];
            if (grid[x][y] == 'E') {
                return distance;
            }
            for (int[] dir : directions) {
                int newX = x + dir[0];
                int newY = y + dir[1];
                if (newX >= 0 && newX < N && newY >= 0 && newY < M && !visited[newX][newY] && (grid[newX][newY] == '0' || grid[newX][newY] == 'E')) {
                    visited[newX][newY] = true;
                    queue.offer(new int[]{newX, newY, distance + 1});
                }
            }
        }
        return -1;
    }
}

