        cin >> A >> B;
        graph[A].push_back(B);
        in_degree[B]++;
    }
    int K;
    cin >> K;
    unordered_map<int, unordered_set<int>> workers;
    for (int i = 0; i < K; ++i) {
        int task_count;
        cin >> task_count;
        for (int j = 0; j < task_count; ++j) {
            int task;
