            workers[i].insert(task);
        }
    }
    queue<int> q;
    for (int i = 1; i <= N; ++i) {
        if (in_degree[i] == 0) {
            bool assigned = false;
            for (const auto& worker : workers) {
                if (worker.second.count(i)) {
                    assigned = true;
                    break;
                }
            }
            if (assigned) {
                q.push(i);
            }
        }
    }
