        }
        while (front != rear) {
            int minIndex = front;
            for (int j = front; j != rear; j = (j + 1) % N) {
                if (queue[j].priority < queue[minIndex].priority) {
                    minIndex = j;
                }
            }
            printf("Processed: %s (Priority: %d)
", queue[minIndex].content, queue[minIndex].priority);
            front = (minIndex + 1) % N;
            if (front == rear) {
                printf("Current Queue: []
");
            } else {
                printf("Current Queue: [");
                for (int k = front; k != rear; k = (k + 1) % N) {
                    printf("%s (Priority: %d)%s", queue[k].content, queue[k].priority, (k + 1) % N == rear ? "" : ", ");
                }
                printf("]
");
            }
            break;
        }
    }
    return 0;
}

