        int N = scanner.nextInt();
        int Q = scanner.nextInt();
        PriorityQueue<Request> queue = new PriorityQueue<>(N, Comparator.comparingInt(r -> r.priority));

        for (int i = 0; i < Q; i++) {
            int priority = scanner.nextInt();
            String content = scanner.next();
            if (queue.size() >= N) {
                System.out.println("Queue is full");
            } else {
                queue.offer(new Request(priority, content));
            }
            while (!queue.isEmpty()) {
                Request request = queue.poll();
                System.out.println("Processed: " + request.content + " (Priority: " + request.priority + ")");
                break;
            }
            System.out.print("Current Queue: [");
            boolean first = true;
            for (Request req : queue) {
                if (!first) System.out.print(", ");
                System.out.print(req.content + " (Priority: " + req.priority + ")");
                first = false;
            }
            System.out.println("]");
        }
        scanner.close();
    }
    static class Request {
        int priority;
        String content;
        Request(int priority, String content) {
            this.priority = priority;
            this.content = content;
        }
    }
}

