    std::vector<std::string> history;
    std::string currentText;
    for (int i = 0; i < M; ++i) {
        std::string command;
        std::cin >> command;
        if (command == "ADD") {
            std::string text;
            std::cin >> text;
            if (history.size() == N) {
                history.erase(history.begin());
            }
            history.push_back(text);
            currentText += text + " ";
        } else if (command == "UNDO") {
            if (!history.empty()) {
                std::string lastAdded = history.back();
                history.pop_back();
                size_t pos = currentText.rfind(lastAdded);
                if (pos != std::string::npos) {
                    currentText.erase(pos, lastAdded.length() + 1);
                }
            }
        }
    }
    std::cout << currentText << std::endl;
    return 0;
}

