#include <stdlib.h>
#include <string.h>
int main() {
    int N, Q;
    scanf("%d %d", &N, &Q);
    int *collection = (int *)malloc(N * sizeof(int));
    int size = 0;
    for (int i = 0; i < Q; i++) {
        char operation[10];
        int cardID;
        scanf("%s %d", operation, &cardID);
        if (strcmp(operation, "ADD") == 0) {
            if (size < N) {
                collection[size++] = cardID;
            } else {
                // Remove the oldest card
                for (int j = 1; j < N; j++) {
                    collection[j - 1] = collection[j];
                }
                collection[N - 1] = cardID;
            }
        } else if (strcmp(operation, "REMOVE") == 0) {
            int found = 0;
            for (int j = 0; j < size; j++) {
                if (collection[j] == cardID) {
                    found = 1;
                    for (int k = j; k < size - 1; k++) {
                        collection[k] = collection[k + 1];
                    }
                    size--;
                    break;
                }
            }
            if (!found) {
                printf("Card %d not found
", cardID);
            }
        }
        // Sort collection
        for (int j = 0; j < size - 1; j++) {
            for (int k = j + 1; k < size; k++) {
                if (collection[j] > collection[k]) {
                    int temp = collection[j];
                    collection[j] = collection[k];
                    collection[k] = temp;
                }
            }
        }
        // Output collection
        if (size == 0) {
            printf("Empty
");
