#include <stdio.h>
#include <stdlib.h>
typedef struct {
    int id;
    int stock;
} Product;
void swap(Product *a, Product *b) {
    Product temp = *a;
    *a = *b;
    *b = temp;
}
void heapify(Product arr[], int n, int i) {
    int largest = i;
    int left = 2 * i + 1;
    int right = 2 * i + 2;
    if (left < n && arr[left].stock > arr[largest].stock) {
        largest = left;
    }
    if (right < n && arr[right].stock > arr[largest].stock) {
        largest = right;
    }
    if (largest != i) {
        swap(&arr[i], &arr[largest]);
        heapify(arr, n, largest);
    }
}
void heapSort(Product arr[], int n) {
    for (int i = n / 2 - 1; i >= 0; i--) {
        heapify(arr, n, i);
    }
    for (int i = n - 1; i > 0; i--) {
        swap(&arr[0], &arr[i]);
        heapify(arr, i, 0);
    }
}
int main() {
    int M, N;
    scanf("%d", &M);
    Product *products = (Product *)malloc(M * sizeof(Product));
    for (int i = 0; i < M; i++) {
        scanf("%d %d", &products[i].id, &products[i].stock);
    }
    scanf("%d", &N);
    heapSort(products, M);
    for (int i = M - 1; i >= M - N; i--) {
        printf("%d
", products[i].id);
    }
    free(products);
    return 0;
}

