        int N = scanner.nextInt();
        // ヒープソートを使用して在庫数でソート
        PriorityQueue<int[]> maxHeap = new PriorityQueue<>((a, b) -> b[1] - a[1]);
        maxHeap.addAll(products);
        // 上位N商品の出力
        for (int i = 0; i < N; i++) {
            int[] product = maxHeap.poll();
            System.out.println(product[0]);
        }
    }
}

