    int valid_count = 0;
    for (int i = 0; i < N; i++) {
        scanf("%s", ticket);
        int len = strlen(ticket);
        int is_valid = 1;
        // Check for leading or trailing symbols
        if (strchr("-_!", ticket[0]) || strchr("-_!", ticket[len - 1])) {
            is_valid = 0;
        }
        // Check for consecutive symbols and normalize to lowercase
        for (int j = 0; j < len; j++) {
            ticket[j] = tolower(ticket[j]);
            if (j > 0 && strchr("-_!", ticket[j]) && ticket[j] == ticket[j - 1]) {
                is_valid = 0;
                break;
            }
        }
        if (is_valid) {
            valid_count++;
        }
    }
    printf("%d
", valid_count);
    return 0;
}

