public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        int validCount = 0;
        for (int i = 0; i < N; i++) {
            String code = scanner.nextLine().toLowerCase();
            if (isValid(code)) {
                validCount++;
            }
        }
        System.out.println(validCount);
        scanner.close();
    }
    private static boolean isValid(String code) {
        if (code.length() == 0 || code.charAt(0) == '-' || code.charAt(0) == '_' || code.charAt(0) == '!') {
            return false;
        }
        if (code.charAt(code.length() - 1) == '-' || code.charAt(code.length() - 1) == '_' || code.charAt(code.length() - 1) == '!') {
            return false;
        }
        for (int j = 1; j < code.length(); j++) {
            if ((code.charAt(j) == '-' || code.charAt(j) == '_' || code.charAt(j) == '!') && 
                (code.charAt(j - 1) == '-' || code.charAt(j - 1) == '_' || code.charAt(j - 1) == '!')) {
                return false;
            }
        }
        return true;
    }
}

