#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_DEPARTMENTS 26
#define MAX_OPERATIONS 1000
typedef struct Stack {
    int data[MAX_OPERATIONS];
    int top;
} Stack;
void push(Stack *s, int value) {
    s->data[++(s->top)] = value;
}
int pop(Stack *s) {
    return s->data[(s->top)--];
}
int main() {
    int N;
    scanf("%d", &N);
    Stack stacks[MAX_DEPARTMENTS];
    for (int i = 0; i < MAX_DEPARTMENTS; i++) {
        stacks[i].top = -1;
    }
    for (int i = 0; i < N; i++) {
        char operation[2], department;
        int amount;
        scanf(" %s", operation);
        if (operation[0] == 'P') {
            scanf(" %c %d", &department, &amount);
            push(&stacks[department - 'A'], amount);
        } else if (operation[0] == 'R') {
            scanf(" %c", &department);
            pop(&stacks[department - 'A']);
        }
    }
    for (int i = 0; i < MAX_DEPARTMENTS; i++) {
        if (stacks[i].top != -1) {
            int total = 0;
            for (int j = 0; j <= stacks[i].top; j++) {
                total += stacks[i].data[j];
            }
            printf("%c: %d
", 'A' + i, total);
        }
    }
    return 0;
}

