import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        scanner.nextLine();
        Map<String, Stack<Integer>> departmentExpenses = new HashMap<>();
        for (int i = 0; i < N; i++) {
            String[] command = scanner.nextLine().split(" ");
            String action = command[0];
            String department = command[1];
            if (action.equals("P")) {
                int amount = Integer.parseInt(command[2]);
                departmentExpenses.putIfAbsent(department, new Stack<>());
                departmentExpenses.get(department).push(amount);
            } else if (action.equals("R")) {
                if (departmentExpenses.containsKey(department) && !departmentExpenses.get(department).isEmpty()) {
                    departmentExpenses.get(department).pop();
                }
            }
        }
        for (Map.Entry<String, Stack<Integer>> entry : departmentExpenses.entrySet()) {
            String dept = entry.getKey();
            Stack<Integer> expenses = entry.getValue();
            int total = 0;
            for (int expense : expenses) {
                total += expense;
