#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
int n, m;
char maze[MAX][MAX];
int visited[MAX][MAX];
int stack[MAX * MAX][2];
int top = -1;
void push(int x, int y) {
    stack[++top][0] = x;
    stack[top][1] = y;
}
int pop(int *x, int *y) {
    if (top < 0) return 0;
    *x = stack[top][0];
    *y = stack[top--][1];
    return 1;
}
int is_valid(int x, int y) {
    return (x >= 0 && x < n && y >= 0 && y < m && maze[x][y] != '#' && !visited[x][y]);
}
int main() {
    scanf("%d %d", &n, &m);
    int start_x, start_y, goal_x, goal_y;
    for (int i = 0; i < n; i++) {
        scanf("%s", maze[i]);
        for (int j = 0; j < m; j++) {
            if (maze[i][j] == 'S') {
                start_x = i;
                start_y = j;
            } else if (maze[i][j] == 'G') {
                goal_x = i;
                goal_y = j;
            }
        }
    }
    push(start_x, start_y);
    visited[start_x][start_y] = 1;
    int found = 0;
    int path[MAX * MAX][2];
    int path_len = 0;
    while (top >= 0) {
        int x, y;
        pop(&x, &y);
        path[path_len][0] = x;
        path[path_len++][1] = y;
        if (x == goal_x && y == goal_y) {
            found = 1;
            break;
        }
        int directions[4][2] = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};
        for (int i = 0; i < 4; i++) {
            int new_x = x + directions[i][0];
            int new_y = y + directions[i][1];
            if (is_valid(new_x, new_y)) {
                push(new_x, new_y);
                visited[new_x][new_y] = 1;
            }
        }
    }
    if (found) {
        for (int i = 0; i < path_len; i++) {
            printf("(%d,%d)%s", path[i][0], path[i][1], (i == path_len - 1) ? "" : "->");
        }
    } else {
        printf("No path found");
    }
    return 0;
}

