import java.util.*;
public class MazeSolver {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        scanner.nextLine();
        char[][] maze = new char[N][M];
        int startX = 0, startY = 0, goalX = 0, goalY = 0;
        for (int i = 0; i < N; i++) {
            String line = scanner.nextLine();
            maze[i] = line.toCharArray();
            for (int j = 0; j < M; j++) {
                if (line.charAt(j) == 'S') {
                    startX = i;
                    startY = j;
                } else if (line.charAt(j) == 'G') {
                    goalX = i;
                    goalY = j;
                }
            }
        }
        Stack<String> path = new Stack<>();
        boolean[][] visited = new boolean[N][M];
        path.push(startX + "," + startY);
        visited[startX][startY] = true;
        while (!path.isEmpty()) {
            String current = path.peek();
            String[] parts = current.split(",");
            int x = Integer.parseInt(parts[0]);
            int y = Integer.parseInt(parts[1]);
            if (x == goalX && y == goalY) {
                break;
            }
            boolean moved = false;
            int[] dx = {-1, 1, 0, 0};
            int[] dy = {0, 0, -1, 1};
            for (int i = 0; i < 4; i++) {
                int newX = x + dx[i];
                int newY = y + dy[i];
                if (newX >= 0 && newX < N && newY >= 0 && newY < M && maze[newX][newY] != '#' && !visited[newX][newY]) {
                    path.push(newX + "," + newY);
                    visited[newX][newY] = true;
                    moved = true;
                    break;
                }
            }
            if (!moved) {
                path.pop();
            }
        }
        StringBuilder result = new StringBuilder();
        while (!path.isEmpty()) {
            String[] parts = path.remove(0).split(",");
            result.append("(").append(parts[0]).append(",").append(parts[1]).append(")").append(path.isEmpty() ? "" : "->");
        }
        System.out.println(result);
    }
}

