    for (int i = 0; i < N; i++) {
        scanf("%d", &scores[i]);
    }
    // Selection sort with stack
    int stack[N];
    int stack_size = 0;
    for (int i = 0; i < N; i++) {
        int min_index = i;
        for (int j = i + 1; j < N; j++) {
            if (scores[j] < scores[min_index]) {
                min_index = j;
            }
        }
        // Swap the found minimum element with the first element
        int temp = scores[min_index];
        scores[min_index] = scores[i];
        scores[i] = temp;
        // Push the current minimum to stack
        stack[stack_size++] = scores[i];
    }
    // Pop from stack to print in descending order
    for (int i = stack_size - 1; i >= 0; i--) {
        printf("%d
", stack[i]);
    }
    return 0;
}

