    std::vector<std::string> results;
    while (!s.empty()) {
        auto [x, y] = s.top();
        if (x == N - 1 && y == M - 1) {
            std::string result;
            for (auto [px, py] : path) {
                result += "(" + std::to_string(px) + "," + std::to_string(py) + ") ";
            }
            results.push_back(result);
        }
        bool found = false;
        for (auto [dx, dy] : {{1, 0}, {0, 1}, {-1, 0}, {0, -1}}) {
