                path.push_back({nx, ny});
                maze[nx][ny] = 1; // mark as visited
                found = true;
                break;
            }
        }
        if (!found) {
            s.pop();
            path.pop_back();
            if (!path.empty()) {
                maze[path.back().first][path.back().second] = 0; // backtrack
            }
        }
    }
