import java.util.*;
public class MazeSolver {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        int[][] maze = new int[N][M];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                maze[i][j] = scanner.nextInt();
            }
        }
        List<List<int[]>> paths = new ArrayList<>();
        boolean[][] visited = new boolean[N][M];
        Stack<int[]> stack = new Stack<>();
        stack.push(new int[]{0, 0});
        visited[0][0] = true;
        while (!stack.isEmpty()) {
            int[] current = stack.peek();
            int x = current[0];
            int y = current[1];
            if (x == N - 1 && y == M - 1) {
                List<int[]> path = new ArrayList<>(stack);
                paths.add(path.toArray(new int[path.size()][]));
                stack.pop();
                continue;
            }
            boolean foundNext = false;
            for (int[] move : new int[][]{{1, 0}, {0, 1}, {-1, 0}, {0, -1}}) {
                int newX = x + move[0];
                int newY = y + move[1];
                if (newX >= 0 && newX < N && newY >= 0 && newY < M && maze[newX][newY] == 0 && !visited[newX][newY]) {
                    stack.push(new int[]{newX, newY});
                    visited[newX][newY] = true;
                    foundNext = true;
                    break;
                }
            }
            if (!foundNext) {
                visited[x][y] = false;
                stack.pop();
            }
        }
        for (List<int[]> path : paths) {
            for (int[] position : path) {
                System.out.print("(" + position[0] + "," + position[1] + ") ");
            }
            System.out.println();
        }
    }
}

