import java.util.*;
public class VotingSystem {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        Stack<String> votes = new Stack<>();
        Map<String, Integer> voteCount = new HashMap<>();
        for (int i = 0; i < N; i++) {
            String input = scanner.nextLine();
            if (input.equals("undo")) {
                if (!votes.isEmpty()) {
                    String lastVote = votes.pop();
                    voteCount.put(lastVote, voteCount.get(lastVote) - 1);
                }
            } else {
                votes.push(input);
                voteCount.put(input, voteCount.getOrDefault(input, 0) + 1);
            }
        }
        // Reporting the results
        List<Map.Entry<String, Integer>> sortedVotes = new ArrayList<>(voteCount.entrySet());
        sortedVotes.sort((a, b) -> {
            int cmp = b.getValue().compareTo(a.getValue());
            if (cmp == 0) {
                return a.getKey().compareTo(b.getKey());
            }
            return cmp;
        });
        for (int i = 0; i < Math.min(3, sortedVotes.size()); i++) {
            System.out.println(sortedVotes.get(i).getKey());
        }
    }
}

