    for (int i = 0; i < N; ++i) {
        cin >> items[i];
    }
    for (int i = N - 1; i >= 0; --i) {
        s.push(items[i]);
    }
    int M;
    cin >> M;
    vector<int> pickingList(M);
    for (int i = 0; i < M; ++i) {
        cin >> pickingList[i];
    }
    for (int i = 0; i < M; ++i) {
        if (s.empty() || s.top() != pickingList[i]) {
            cout << pickingList[i];
            return 0;
        }
        s.pop();
    }
    cout << "完了";
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Stack<Integer> stack = new Stack<>();
        for (int i = 0; i < N; i++) {
            stack.push(scanner.nextInt());
        }
        int M = scanner.nextInt();
        List<Integer> pickingList = new ArrayList<>();
        for (int i = 0; i < M; i++) {
            pickingList.add(scanner.nextInt());
        }
        for (int item : pickingList) {
            if (!stack.isEmpty() && stack.peek() == item) {
                stack.pop();
            } else {
                boolean found = false;
                Stack<Integer> tempStack = new Stack<>();
                while (!stack.isEmpty()) {
                    if (stack.peek() == item) {
                        found = true;
                        stack.pop();
                        break;
                    } else {
                        tempStack.push(stack.pop());
                    }
                }
                while (!tempStack.isEmpty()) {
                    stack.push(tempStack.pop());
                }
                if (!found) {
                    System.out.println(item);
                    return;
                }
            }
        }
        System.out.println("完了");
    }
}

