int main() {
    char *logs[] = {
        "2022-05-01 12:00:00 INFO User123 logged in",
        "2022-05-01 12:05:00 ERROR User456 failed to load",
        "2022-05-01 12:10:00 INFO User123 logged out"
    };
    int num_logs = sizeof(logs) / sizeof(logs[0]);
    char users[100][20];
    int login_count[100] = {0};
    int error_count[100] = {0};
    int user_index = 0;
    for (int i = 0; i < num_logs; i++) {
        char *log = logs[i];
        char *token = strtok(log, " ");
        while (token != NULL) {
            if (strcmp(token, "INFO") == 0) {
                token = strtok(NULL, " ");
                token = strtok(NULL, " ");
                if (strstr(token, "logged in") != NULL) {
                    for (int j = 0; j < user_index; j++) {
                        if (strcmp(users[j], token) == 0) {
                            login_count[j]++;
                            break;
                        }
                    }
                    strcpy(users[user_index], token);
                    login_count[user_index]++;
                    user_index++;
                }
            }
            if (strcmp(token, "ERROR") == 0) {
                token = strtok(NULL, " ");
                if (strstr(token, "failed to load") != NULL) {
                    for (int j = 0; j < user_index; j++) {
                        if (strcmp(users[j], token) == 0) {
                            error_count[j]++;
                            break;
                        }
                    }
                    strcpy(users[user_index], token);
                    error_count[user_index]++;
                    user_index++;
                }
            }
            token = strtok(NULL, " ");
        }
    }
    printf("{
");
    for (int i = 0; i < user_index; i++) {
        printf("  '%s': {'login_count': %d, 'error_count': %d},
