#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    char maze[MAX][MAX];
    for (int i = 0; i < N; i++) {
        scanf("%s", maze[i]);
    }
    int directions[4][2] = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};
    int visited[MAX][MAX] = {0};
    int path[MAX * MAX][2];
    int path_index = 0;
    int found = 0;
    void dfs(int x, int y) {
        if (x == N - 1 && y == M - 1) {
            found = 1;
            return;
        }
        visited[x][y] = 1;
        path[path_index][0] = x;
        path[path_index][1] = y;
        path_index++;
        for (int i = 0; i < 4; i++) {
            int new_x = x + directions[i][0];
            int new_y = y + directions[i][1];
            if (new_x >= 0 && new_x < N && new_y >= 0 && new_y < M && maze[new_x][new_y] == '0' && !visited[new_x][new_y]) {
                dfs(new_x, new_y);
                if (found) return;
            }
        }
        path_index--;
        visited[x][y] = 0;
    }
    dfs(0, 0);
    if (found) {
        printf("[");
        for (int i = 0; i < path_index; i++) {
            printf("(%d, %d)%s", path[i][0], path[i][1], (i == path_index - 1) ? "" : ", ");
        }
        printf("]");
    } else {
        printf("[]");
    }
    return 0;
}

import java.util.*;
public class MazeSolver {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        scanner.nextLine();
        char[][] maze = new char[N][M];
        for (int i = 0; i < N; i++) {
            maze[i] = scanner.nextLine().replaceAll(" ", "").toCharArray();
        }
        List<int[]> path = new ArrayList<>();
        boolean[][] visited = new boolean[N][M];
        if (findPath(maze, 0, 0, N, M, path, visited)) {
            System.out.print(path);
        } else {
            System.out.print(Collections.emptyList());
        }
    }
    private static boolean findPath(char[][] maze, int x, int y, int N, int M, List<int[]> path, boolean[][] visited) {
        if (x < 0 || x >= N || y < 0 || y >= M || maze[x][y] == '1' || visited[x][y]) {
            return false;
        }
        path.add(new int[]{x, y});
        visited[x][y] = true;
        if (x == N - 1 && y == M - 1) {
            return true;
        }
        if (findPath(maze, x + 1, y, N, M, path, visited) || 
            findPath(maze, x, y + 1, N, M, path, visited) || 
            findPath(maze, x - 1, y, N, M, path, visited) || 
            findPath(maze, x, y - 1, N, M, path, visited)) {
            return true;
        }
        path.remove(path.size() - 1);
        return false;
    }
}

