                can_install = 0;
                break;
            }
        }
        if (can_install) {
            min_index = (min_index == -1) ? (i + 1) : (min_index < (i + 1) ? min_index : (i + 1));
        }
    }
    if (min_index != -1) {
        printf("YES %d
", min_index);
    } else {
        printf("NO
");
    }
    for (int i = 0; i < N; i++) {
        free(dependencies[i]);
    }
    free(dependencies);
    free(dependency_count);
