#define MAX 100
int maze[MAX][MAX];
int visited[MAX][MAX];
int N, M;
typedef struct {
    int x, y, dist;
} Node;
int isValid(int x, int y) {
    return (x >= 0 && x < N && y >= 0 && y < M && maze[x][y] == 0 && !visited[x][y]);
}
int dfs(int x, int y, int dist) {
    if (x == N - 1 && y == M - 1) return dist;
    visited[x][y] = 1;
    int minDist = -1;
    int directions[4][2] = {{1, 0}, {-1, 0}, {0, 1}, {0, -1}};
    for (int i = 0; i < 4; i++) {
        int newX = x + directions[i][0];
        int newY = y + directions[i][1];
        if (isValid(newX, newY)) {
            int result = dfs(newX, newY, dist + 1);
            if (result != -1 && (minDist == -1 || result < minDist)) {
                minDist = result;
            }
        }
    }
    visited[x][y] = 0;
    return minDist;
}
