import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] samples = new int[N];
        for (int i = 0; i < N; i++) {
            samples[i] = scanner.nextInt();
        }
        int gcd = samples[0];
        boolean isCommon = true;
        for (int i = 1; i < N; i++) {
            gcd = findGCD(gcd, samples[i]);
            if (samples[i] != samples[0]) {
                isCommon = false;
            }
        }
        System.out.println(gcd);
        if (isCommon) {
            System.out.println("全てのサンプル数は共通しています。");
        } else {
            System.out.println("共通するサンプル数はありません。");
        }
    }
    private static int findGCD(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}

