#include <stdio.h>
#include <stdlib.h>
typedef struct {
    int days;
    int priority;
    int index;
} Destination;
int compare(const void *a, const void *b) {
    Destination *destA = (Destination *)a;
    Destination *destB = (Destination *)b;
    if (destA->priority != destB->priority) {
        return destB->priority - destA->priority;
    }
    return destA->index - destB->index;
}
int main() {
    int N;
    scanf("%d", &N);
    Destination destinations[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &destinations[i].days, &destinations[i].priority);
        destinations[i].index = i + 1;
    }
    qsort(destinations, N, sizeof(Destination), compare);
    for (int i = 0; i < N; i++) {
        if (destinations[i].days >= 1) {
            if (destinations[i].days >= 2 && destinations[i].priority == 1) {
                printf("%d
", destinations[i].index);
            } else if (destinations[i].days < 2 && destinations[i].priority != 1) {
                printf("%d
", destinations[i].index);
            }
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <algorithm>
struct Location {
    int days;
    int priority;
    int index;
};
int main() {
    int N;
    std::cin >> N;
    std::vector<Location> locations;
    for (int i = 0; i < N; ++i) {
        int D, P;
        std::cin >> D >> P;
        if (D > 0) {
            locations.push_back({D, P, i + 1});
        }
    }
    // 必ず訪問する候補地を追加
    std::vector<Location> mustVisit;
    for (const auto& loc : locations) {
        if (loc.days >= 2 && loc.priority == 1) {
            mustVisit.push_back(loc);
        }
    }
    // 残りの候補地を優先度でソート
    std::sort(locations.begin(), locations.end()(const Location &a, const Location &b) {
        return a.priority < b.priority;
    });
    // 必ず訪問する候補地を出力
    for (const auto& loc : mustVisit) {
        std::cout << loc.index << std::endl;
    }
    // 残りの候補地を出力
    for (const auto& loc : locations) {
        if (std::find(mustVisit.begin(), mustVisit.end(), loc) == mustVisit.end()) {
            std::cout << loc.index << std::endl;
        }
    }
    return 0;
}

import java.util.*;
public class TravelPlan {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        List<int[]> places = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            int D = scanner.nextInt();
            int P = scanner.nextInt();
            if (D > 0) {
                places.add(new int[]{D, P, i + 1});
            }
        }
        // Sort by priority (descending) and then by index (ascending)
        places.sort((a, b) -> {
            if (b[1] != a[1]) {
                return Integer.compare(b[1], a[1]);
            }
            return Integer.compare(a[2], b[2]);
        });
        List<Integer> result = new ArrayList<>();
        // Visit places according to the rules
        for (int[] place : places) {
            int D = place[0];
            int P = place[1];
            int idx = place[2];
            if (D >= 2 && P == 1) {
                result.add(idx);
            } else if (P > 1) {
                result.add(idx);
            }
        }
        for (int idx : result) {
            System.out.println(idx);
        }
    }
}

