#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_PACKAGES 100
typedef struct Package {
    char name[50];
    char dependencies[10][50];
    int dep_count;
} Package;
Package packages[MAX_PACKAGES];
int package_count = 0;
int visited[MAX_PACKAGES];
int in_stack[MAX_PACKAGES];
void dfs(int index) {
    visited[index] = 1;
    in_stack[index] = 1;
    for (int i = 0; i < packages[index].dep_count; i++) {
        for (int j = 0; j < package_count; j++) {
            if (strcmp(packages[index].dependencies[i], packages[j].name) == 0) {
                if (in_stack[j]) {
                    printf("%s
", packages[j].name);
                    exit(0);
                }
                if (!visited[j]) {
                    dfs(j);
                }
            }
        }
    }
    in_stack[index] = 0;
    for (int i = 0; i < packages[index].dep_count; i++) {
        printf("%s
", packages[index].dependencies[i]);
    }
}
int main() {
    scanf("%d", &package_count);
    for (int i = 0; i < package_count; i++) {
        scanf("%s", packages[i].name);
        packages[i].dep_count = 0;
        char line[500];
        scanf("%s", line);
        char *token = strtok(line, ",");
        while (token != NULL) {
            strcpy(packages[i].dependencies[packages[i].dep_count++], token);
            token = strtok(NULL, ",");
        }
    }
    memset(visited, 0, sizeof(visited));
    memset(in_stack, 0, sizeof(in_stack));
    for (int i = 0; i < package_count; i++) {
        if (!visited[i]) {
            dfs(i);
        }
    }
    return 0;
}

#include <iostream>
#include <unordered_map>
#include <unordered_set>
#include <vector>
#include <sstream>
using namespace std;
int main() {
    int N;
    cin >> N;
    cin.ignore();
    unordered_map<string, vector<string>> dependencies;
    unordered_set<string> visited;
    unordered_set<string> inStack;
    string line;
    for (int i = 0; i < N; ++i) {
        getline(cin, line);
        stringstream ss(line);
        string package;
        getline(ss, package, ' ');
        string depList;
        getline(ss, depList);
        if (!depList.empty()) {
            stringstream depStream(depList);
            string dep;
            while (getline(depStream, dep, ',')) {
                dependencies[package].push_back(dep);
            }
        }
    }
    function<bool(const string&)> dfs = [&](const string& pkg) {
        if (inStack.count(pkg)) {
            cout << pkg << endl;
            return false;
        }
        if (visited.count(pkg)) return true;
        visited.insert(pkg);
        inStack.insert(pkg);
        for (const auto& dep : dependencies[pkg]) {
            if (!dfs(dep)) return false;
        }
        inStack.erase(pkg);
        return true;
    };
    for (const auto& [pkg, _] : dependencies) {
        if (!visited.count(pkg)) {
            if (!dfs(pkg)) return 0;
        }
    }
    for (const auto& pkg : dependencies) {
        cout << pkg.first << endl;
    }
    return 0;
}

import java.util.*;
public class DependencyResolver {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        Map<String, List<String>> dependencies = new HashMap<>();
        Set<String> visited = new HashSet<>();
        Set<String> recursionStack = new HashSet<>();
        for (int i = 0; i < N; i++) {
            String[] parts = scanner.nextLine().split(" ");
            String packageName = parts[0];
            List<String> depList = parts.length > 1 && !parts[1].isEmpty() ? Arrays.asList(parts[1].split(",")) : new ArrayList<>();
            dependencies.put(packageName, depList);
        }
        for (String packageName : dependencies.keySet()) {
            if (!visited.contains(packageName)) {
                if (dfs(packageName, dependencies, visited, recursionStack)) {
                    return;
                }
            }
        }
    }
    private static boolean dfs(String packageName, Map<String, List<String>> dependencies, Set<String> visited, Set<String> recursionStack) {
        visited.add(packageName);
        recursionStack.add(packageName);
        for (String dep : dependencies.get(packageName)) {
            if (!visited.contains(dep)) {
                if (dfs(dep, dependencies, visited, recursionStack)) {
                    return true;
                }
            } else if (recursionStack.contains(dep)) {
                System.out.println(dep);
                return true;
            }
        }
        recursionStack.remove(packageName);
        return false;
    }
}

