import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        List<String> places = new ArrayList<>();
        List<Integer> days = new ArrayList<>();
        for (int i = 0; i < M; i++) {
            String place = scanner.next();
            int day = scanner.nextInt();
            places.add(place);
            days.add(day);
        }
        List<String> selectedPlaces = new ArrayList<>();
        int totalDays = 0;
        // Sort places alphabetically
        List<Map.Entry<String, Integer>> placeDays = new ArrayList<>();
        for (int i = 0; i < M; i++) {
            placeDays.add(new AbstractMap.SimpleEntry<>(places.get(i), days.get(i)));
        }
        Collections.sort(placeDays, Map.Entry.comparingByKey());
        // Select places within the limit of N days
        for (Map.Entry<String, Integer> entry : placeDays) {
            if (totalDays + entry.getValue() <= N) {
                selectedPlaces.add(entry.getKey());
                totalDays += entry.getValue();
            }
        }
        // Output result
        if (selectedPlaces.isEmpty()) {
            System.out.println("なし");
        } else {
            System.out.println(String.join(",", selectedPlaces));
        }
    }
}

