import java.util.HashMap;
import java.util.Map;
public class Library {
    public static void main(String[] args) {
        String[][] libraryItems = {{"Python Programming", "John Doe"}, {"Data Structures", "Jane Smith"}, {"Algorithms", "Alice Johnson"}};
        Map<String, String[]> itemMap = new HashMap<>();
        Map<String, Boolean> availabilityMap = new HashMap<>();
        for (String[] item : libraryItems) {
            itemMap.put(item[0], item);
            availabilityMap.put(item[0], true);
        }
        System.out.println(borrowItem(itemMap, availabilityMap, "Python Programming"));
        System.out.println(returnItem(itemMap, availabilityMap, "Data Structures"));
        System.out.println(searchItem(itemMap, "Algorithms"));
    }
    public static String borrowItem(Map<String, String[]> itemMap, Map<String, Boolean> availabilityMap, String title) {
        if (itemMap.containsKey(title) && availabilityMap.get(title)) {
            availabilityMap.put(title, false);
            return "アイテム '" + title + "' が貸出されました。";
        }
        return "アイテム '" + title + "' は貸出できません。";
    }
    public static String returnItem(Map<String, String[]> itemMap, Map<String, Boolean> availabilityMap, String title) {
        if (itemMap.containsKey(title) && !availabilityMap.get(title)) {
            availabilityMap.put(title, true);
            return "アイテム '" + title + "' が返却されました。";
        }
        return "アイテム '" + title + "' は返却できません。";
    }
    public static String searchItem(Map<String, String[]> itemMap, String title) {
        if (itemMap.containsKey(title)) {
            return "アイテム '" + title + "' が見つかりました: [" + String.join(", ", itemMap.get(title)) + "]";
        }
        return "アイテム '" + title + "' は見つかりませんでした。";
    }
}

