#include <stdio.h>
#include <stdlib.h>
typedef struct {
    int arrival_time;
    int entry_time;
    int index;
} Visitor;
int compare(const void *a, const void *b) {
    Visitor *visitorA = (Visitor *)a;
    Visitor *visitorB = (Visitor *)b;
    if (visitorA->entry_time != visitorB->entry_time) {
        return visitorA->entry_time - visitorB->entry_time;
    }
    return visitorA->arrival_time - visitorB->arrival_time;
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Visitor visitors[N];
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &visitors[i].arrival_time, &visitors[i].entry_time);
        visitors[i].index = i;
    }
    qsort(visitors, N, sizeof(Visitor), compare);
    for (int i = 0; i < N && i < M; i++) {
        printf("%d
", visitors[i].index);
    }
    return 0;
}

