        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int M = scanner.nextInt();
        int[][] visitors = new int[N][3]; // [arrival_time, entry_time, index]
        for (int i = 0; i < N; i++) {
            visitors[i][0] = scanner.nextInt(); // arrival time
            visitors[i][1] = scanner.nextInt(); // entry time
            visitors[i][2] = i; // original index
        }
        Arrays.sort(visitors, (a, b) -> {
            if (a[1] != b[1]) return Integer.compare(a[1], b[1]);
            return Integer.compare(a[0], b[0]);
        });
        List<Integer> result = new ArrayList<>();
        for (int i = 0; i < N && result.size() < M; i++) {
            if (i == 0 || visitors[i][1] != visitors[i - 1][1] || result.size() < M) {
                result.add(visitors[i][2]);
            }
        }
        for (int index : result) {
            System.out.println(index);
        }
    }
}

