#include <stdio.h>
#include <string.h>
int main() {
    int N;
    scanf("%d", &N);
    char items[N][31];
    int stock[N];
    for (int i = 0; i < N; i++) {
        scanf("%s %d", items[i], &stock[i]);
    }
    for (int i = 0; i < N - 1; i++) {
        for (int j = 0; j < N - 1 - i; j++) {
            if (stock[j] < stock[j + 1]) {
                // Swap stock
                int temp_stock = stock[j];
                stock[j] = stock[j + 1];
                stock[j + 1] = temp_stock;
                // Swap items
                char temp_item[31];
                strcpy(temp_item, items[j]);
                strcpy(items[j], items[j + 1]);
                strcpy(items[j + 1], temp_item);
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%s %d
", items[i], stock[i]);
    }
    return 0;
}

