    int priority;
} Patient;
int compare(const void *a, const void *b) {
    Patient *p1 = (Patient *)a;
    Patient *p2 = (Patient *)b;
    if (p1->priority != p2->priority) {
        return p2->priority - p1->priority;
    }
    return strcmp(p1->name, p2->name);
}
