    int N;
    scanf("%d", &N);
    Patient patients[N];
    for (int i = 0; i < N; i++) {
        scanf("%s %d", patients[i].name, &patients[i].priority);
    }
    qsort(patients, N, sizeof(Patient), compare);
    for (int i = 0; i < N; i++) {
        printf("%s
", patients[i].name);
    }
    return 0;
}

