import java.util.*;
public class LibraryManagement {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = Integer.parseInt(scanner.nextLine());
        Map<String, Item> library = new HashMap<>();
        for (int i = 0; i < n; i++) {
            String[] itemData = scanner.nextLine().split(" ");
            String title = itemData[0];
            String author = itemData[1];
            boolean isBorrowed = Boolean.parseBoolean(itemData[2]);
            library.put(title, new Item(title, author, isBorrowed));
        }
        int m = Integer.parseInt(scanner.nextLine());
        for (int i = 0; i < m; i++) {
            String[] operation = scanner.nextLine().split(" ");
            String command = operation[0];
            String title = operation[1];
            switch (command) {
                case "ADD":
                    String author = operation[2];
                    boolean status = Boolean.parseBoolean(operation[3]);
                    library.put(title, new Item(title, author, status));
                    System.out.println("アイテムが追加されました");
                    break;
                case "BORROW":
                    Item itemToBorrow = library.get(title);
                    if (itemToBorrow != null) {
                        if (!itemToBorrow.isBorrowed) {
                            itemToBorrow.isBorrowed = true;
                            System.out.println("貸出成功");
                        } else {
                            System.out.println("アイテムは貸出中です");
                        }
                    } else {
                        System.out.println("アイテムが見つかりませんでした");
                    }
                    break;
                case "RETURN":
                    Item itemToReturn = library.get(title);
                    if (itemToReturn != null) {
                        itemToReturn.isBorrowed = false;
                        System.out.println("返却成功");
                    } else {
                        System.out.println("アイテムは存在しません");
                    }
                    break;
                case "SEARCH":
                    Item itemToSearch = library.get(title);
                    if (itemToSearch != null) {
                        System.out.println("タイトル: " + itemToSearch.title + ", 著者: " + itemToSearch.author + ", 貸出状況: " + itemToSearch.isBorrowed);
                    } else {
                        System.out.println("アイテムが見つかりませんでした");
                    }
                    break;
            }
        }
    }
    static class Item {
        String title;
        String author;
        boolean isBorrowed;
        Item(String title, String author, boolean isBorrowed) {
            this.title = title;
            this.author = author;
            this.isBorrowed = isBorrowed;
        }
    }
}

