int main() {
    int N;
    scanf("%d", &N);
    char products[100][100];
    int stock[100];
    for (int i = 0; i < N; i++) {
        scanf("%s %d", products[i], &stock[i]);
    }
    // Sort products by stock
    for (int i = 0; i < N - 1; i++) {
        for (int j = 0; j < N - i - 1; j++) {
            if (stock[j] < stock[j + 1]) {
                // Swap stock
                int temp_stock = stock[j];
                stock[j] = stock[j + 1];
                stock[j + 1] = temp_stock;
                // Swap products
                char temp_product[100];
                strcpy(temp_product, products[j]);
                strcpy(products[j], products[j + 1]);
                strcpy(products[j + 1], temp_product);
            }
        }
    }
    // Output top 3 products
    for (int i = 0; i < (N < 3 ? N : 3); i++) {
        printf("%s
", products[i]);
    }
    return 0;
}

