#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_PACKAGES 100
#define MAX_NAME_LENGTH 50
typedef struct Package {
    char name[MAX_NAME_LENGTH];
    struct Package* dependencies[MAX_PACKAGES];
    int dep_count;
} Package;
Package packages[MAX_PACKAGES];
int package_count = 0;
int visited[MAX_PACKAGES];
void dfs(Package* pkg) {
    visited[package_count++] = 1;
    printf("%s ", pkg->name);
    for (int i = 0; i < pkg->dep_count; i++) {
        if (!visited[pkg->dependencies[i] - packages]) {
            dfs(pkg->dependencies[i]);
        }
    }
}
int main() {
    int N;
    scanf("%d", &N);
    for (int i = 0; i < N; i++) {
        char pkg_name[MAX_NAME_LENGTH];
        scanf("%s", pkg_name);
        strcpy(packages[i].name, pkg_name);
        packages[i].dep_count = 0;
        while (1) {
            char dep_name[MAX_NAME_LENGTH];
            if (scanf("%s", dep_name) == EOF) break;
            if (strcmp(dep_name, "END") == 0) break;
            for (int j = 0; j < i; j++) {
                if (strcmp(packages[j].name, dep_name) == 0) {
                    packages[i].dependencies[packages[i].dep_count++] = &packages[j];
                    break;
                }
            }
        }
    }
    char query[MAX_NAME_LENGTH];
    scanf("%s", query);
    for (int i = 0; i < N; i++) {
        if (strcmp(packages[i].name, query) == 0) {
            memset(visited, 0, sizeof(visited));
            package_count = 0;
            dfs(&packages[i]);
            break;
        }
    }
    return 0;
}

#include <iostream>
#include <vector>
#include <unordered_map>
#include <unordered_set>
#include <stack>
#include <sstream>
using namespace std;
int main() {
    int N;
    cin >> N;
    unordered_map<string, vector<string>> dependencies;
    string package, line;
    getline(cin, line); // to consume the newline after N
    for (int i = 0; i < N; ++i) {
        getline(cin, line);
        istringstream iss(line);
        iss >> package;
        string dep;
        while (iss >> dep) {
            dependencies[package].push_back(dep);
        }
    }
    string target;
    cin >> target;
    unordered_set<string> visited;
    stack<string> s;
    s.push(target);
    while (!s.empty()) {
        string current = s.top();
        s.pop();
        if (visited.find(current) == visited.end()) {
            visited.insert(current);
            for (const string &dep : dependencies[current]) {
                if (visited.find(dep) == visited.end()) {
                    s.push(dep);
                }
            }
        }
    }
    for (const string &pkg : visited) {
        if (pkg != target) {
            cout << pkg << " ";
        }
    }
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        Map<String, List<String>> dependencies = new HashMap<>();
        Set<String> visited = new HashSet<>();
        for (int i = 0; i < N; i++) {
            String[] parts = scanner.nextLine().split(" ");
            String packageName = parts[0];
            List<String> deps = new ArrayList<>();
            for (int j = 1; j < parts.length; j++) {
                deps.add(parts[j]);
            }
            dependencies.put(packageName, deps);
        }
        String targetPackage = scanner.nextLine();
        List<String> result = new ArrayList<>();
        dfs(targetPackage, dependencies, visited, result);
        System.out.println(String.join(" ", result));
    }
    private static void dfs(String packageName, Map<String, List<String>> dependencies, Set<String> visited, List<String> result) {
        if (visited.contains(packageName)) return;
        visited.add(packageName);
        for (String dep : dependencies.getOrDefault(packageName, Collections.emptyList())) {
            dfs(dep, dependencies, visited, result);
        }
        result.add(packageName);
    }
}

