#include <stdio.h>
#include <string.h>
#include <stdlib.h>
int main() {
    char document[1000] = "";
    char history[100][1000];
    int history_index = 0;
    int length = 0;
    char command[50];
    while (fgets(command, sizeof(command), stdin)) {
        command[strcspn(command, "
")] = 0; // 改行を削除
        if (strncmp(command, "add ", 4) == 0) {
            strcpy(history[history_index++], document);
            strcat(document, command + 4);
            length += strlen(command + 4);
        } else if (strncmp(command, "delete ", 7) == 0) {
            int del_length = atoi(command + 7);
            if (del_length > length) del_length = length;
            strcpy(history[history_index++], document);
            document[length - del_length] = '\0';
            length -= del_length;
        } else if (strcmp(command, "undo") == 0) {
            if (history_index > 0) {
                strcpy(document, history[--history_index]);
                length = strlen(document);
            }
        }
    }
    printf("%s
", document);
    return 0;
}

