}

import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class TextEditor {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        StringBuilder document = new StringBuilder();
        List<String> history = new ArrayList<>();
        while (scanner.hasNextLine()) {
            String operation = scanner.nextLine();
            history.add(document.toString());
            if (operation.startsWith("add ")) {
                String textToAdd = operation.substring(4);
                document.append(textToAdd);
            } else if (operation.startsWith("delete ")) {
                int lengthToDelete = Integer.parseInt(operation.split(" ")[1]);
                if (lengthToDelete <= document.length()) {
                    document.delete(document.length() - lengthToDelete, document.length());
                } else {
                    document.setLength(0);
                }
            } else if (operation.equals("undo")) {
                if (!history.isEmpty()) {
                    document = new StringBuilder(history.remove(history.size() - 1));
                }
            }
        }
        System.out.println(document.toString());
    }
}

