import java.util.Random;
public class TrafficSimulation {
    public static void main(String[] args) {
        int simulationTime = 10; // Simulation time in seconds
        String initialState = "red"; // Initial signal state
        int signalChangeCount = 0;
        int carsMoved = 0;
        int timeElapsed = 0;
        String[] states = {"red", "green", "yellow"};
        int[] durations = {5, 3, 2};
        Random random = new Random();
        String currentState = initialState;
        while (timeElapsed < simulationTime) {
            int duration = getDuration(currentState);
            if (timeElapsed + duration > simulationTime) {
                break;
            }
            timeElapsed += duration;
            signalChangeCount++;
            if (currentState.equals("green")) {
                carsMoved += 1;
            } else if (currentState.equals("yellow")) {
                if (random.nextBoolean()) {
                    carsMoved += 1;
                }
            }
            currentState = getNextState(currentState);
        }
        System.out.println(signalChangeCount);
        System.out.println(carsMoved);
    }
    private static int getDuration(String state) {
        switch (state) {
            case "red": return 5;
            case "green": return 3;
            case "yellow": return 2;
            default: return 0;
        }
    }
    private static String getNextState(String currentState) {
