import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] waitTimes = new int[n];
        for (int i = 0; i < n; i++) {
            waitTimes[i] = scanner.nextInt();
        }
        // Sorting using adjacent swap method
        boolean swapped;
        do {
            swapped = false;
            for (int i = 0; i < n - 1; i++) {
                if (waitTimes[i] > waitTimes[i + 1]) {
                    int temp = waitTimes[i];
                    waitTimes[i] = waitTimes[i + 1];
                    waitTimes[i + 1] = temp;
                    swapped = true;
                }
            }
        } while (swapped);
        for (int i = 0; i < n; i++) {
            System.out.print(waitTimes[i]);
            if (i < n - 1) System.out.print(" ");
        }
    }
}

