#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }
    // 挿入ソート
    for (int i = 1; i < n; ++i) {
        int key = arr[i];
        int j = i - 1;
        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j--;
        }
        arr[j + 1] = key;
    }
    // 素数を抽出
    vector<int> primes;
    for (int num : arr) {
        bool is_prime = true;
        if (num < 2) {
            is_prime = false;
        } else {
            for (int j = 2; j * j <= num; ++j) {
                if (num % j == 0) {
                    is_prime = false;
                    break;
                }
            }
        }
        if (is_prime) {
            primes.push_back(num);
        }
    }
    // 結果の出力
    for (int i = 0; i < primes.size(); ++i) {
        if (i > 0) cout << " ";
        cout << primes[i];
    }
    cout << endl;
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        List<Integer> list = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            list.add(scanner.nextInt());
        }
        // Insert Sort
        for (int i = 1; i < list.size(); i++) {
            int key = list.get(i);
            int j = i - 1;
            while (j >= 0 && list.get(j) > key) {
                list.set(j + 1, list.get(j));
                j--;
            }
            list.set(j + 1, key);
        }
        // Extract primes
        List<Integer> primes = new ArrayList<>();
        for (int num : list) {
            if (isPrime(num)) {
                primes.add(num);
            }
        }
        // Output primes
        for (int i = 0; i < primes.size(); i++) {
            System.out.print(primes.get(i));
            if (i < primes.size() - 1) {
                System.out.print(' ');
            }
        }
        System.out.println();
    }
    private static boolean isPrime(int num) {
        if (num <= 1) return false;
        for (int i = 2; i <= Math.sqrt(num); i++) {
            if (num % i == 0) return false;
        }
        return true;
    }
}

