using namespace std;
int main() {
    vector<pair<string, string>> items = {
        {"Pythonプログラミング", "山田太郎"},
        {"デザインパターン", "佐藤花子"},
        {"アルゴリズム", "田中一郎"},
        {"データベース入門", "鈴木次郎"}
    };
    vector<pair<string, string>> borrowed;
    // Borrow item
    string title = "Pythonプログラミング";
    string author = "山田太郎";
    auto it = find_if(items.begin(), items.end(), [&](const pair<string, string>& item) {
        return item.first == title && item.second == author;
    });
    if (it != items.end()) {
        borrowed.push_back(*it);
        cout << "貸出成功: " << title << " by " << author << endl;
    } else {
        cout << "アイテムが見つかりませんでした" << endl;
    }
    // Return item
    title = "Pythonプログラミング";
    author = "山田太郎";
    it = find_if(borrowed.begin(), borrowed.end(), [&](const pair<string, string>& item) {
        return item.first == title && item.second == author;
    });
    if (it != borrowed.end()) {
        borrowed.erase(it);
        cout << "返却成功: " << title << " by " << author << endl;
    } else {
        cout << "そのアイテムは貸出されていません" << endl;
    }
    // Search items
    string query = "デザイン";
    vector<string> results;
    for (const auto& item : items) {
        if (item.first.find(query) != string::npos || item.second.find(query) != string::npos) {
            results.push_back(item.first + " by " + item.second);
        }
    }
    for (const auto& result : results) {
        cout << result << endl;
    }
    return 0;
}

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
public class Library {
    static Map<String, Boolean> items = new HashMap<>();
    static {
        items.put("Pythonプログラミング,山田太郎", true);
        items.put("デザインパターン,佐藤花子", true);
    }
    static List<String> borrowedItems = new ArrayList<>();
    public static void main(String[] args) {
        System.out.println(borrow_item("Pythonプログラミング", "山田太郎"));
        System.out.println(return_item("Pythonプログラミング", "山田太郎"));
        System.out.println(search_items("デザイン"));
        // 新しい操作を追加
        System.out.println(borrow_item("デザインパターン", "佐藤花子"));
        System.out.println(search_items("山田"));
        System.out.println(return_item("デザインパターン", "佐藤花子"));
    }
    public static String borrow_item(String title, String author) {
        String key = title + "," + author;
        if (items.containsKey(key) && items.get(key)) {
            items.put(key, false);
            borrowedItems.add(key);
            return "貸出成功: " + title + " by " + author;
        } else {
            return "アイテムが見つかりませんでした";
        }
    }
    public static String return_item(String title, String author) {
        String key = title + "," + author;
        if (borrowedItems.contains(key)) {
            items.put(key, true);
            borrowedItems.remove(key);
            return "返却成功: " + title + " by " + author;
        } else {
            return "そのアイテムは貸出されていません";
        }
    }
    public static List<String> search_items(String query) {
        List<String> results = new ArrayList<>();
        for (String key : items.keySet()) {
            if (key.toLowerCase().contains(query.toLowerCase()) && items.get(key)) {
                results.add(key.replace(",", " by " ));
            }
        }
        return results;
    }
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main() {
    int N;
    scanf("%d", &N);
    int delays[N];
    int digit_sum = 0;
    int max_delay = 0;
    int min_delay = 1000000;
    double total = 0;
    for (int i = 0; i < N; i++) {
        char delay_str[10];
        scanf("%s", delay_str);
        int delay = atoi(delay_str);
        delays[i] = delay;
        total += delay;
        if (delay > max_delay) max_delay = delay;
        if (delay < min_delay) min_delay = delay;
        for (char *p = delay_str; *p; p++) {
            if (*p >= '0' && *p <= '9') {
                digit_sum += (*p - '0');
            }
        }
    }
    double average_delay = total / N;
    printf("最大遅延: %d, 最小遅延: %d, 平均遅延: %.2f, 数字の合計: %d
", max_delay, min_delay, average_delay, digit_sum);
    return 0;
}

