        std::string time_str = std::to_string(time);
        for (char c : time_str) {
            digit_sum += c - '0';
        }
    }
    std::cout << "最大遅延: " << max_delay << ", 最小遅延: " << min_delay << ", 平均遅延: " << std::fixed << std::setprecision(2) << average_delay << ", 数字の合計: " << digit_sum;
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = Integer.parseInt(scanner.nextLine());
        int maxDelay = Integer.MIN_VALUE;
        int minDelay = Integer.MAX_VALUE;
        int totalDelay = 0;
        int digitSum = 0;
        for (int i = 0; i < N; i++) {
            String delayStr = scanner.nextLine();
            int delay = Integer.parseInt(delayStr.replace("ms", ""));
            maxDelay = Math.max(maxDelay, delay);
            minDelay = Math.min(minDelay, delay);
            totalDelay += delay;
            digitSum += sumOfDigits(delay);
        }
        double averageDelay = (double) totalDelay / N;
        System.out.printf("最大遅延: %d, 最小遅延: %d, 平均遅延: %.2f, 数字の合計: %d
", maxDelay, minDelay, averageDelay, digitSum);
    }
    private static int sumOfDigits(int number) {
        int sum = 0;
        while (number > 0) {
            sum += number % 10;
            number /= 10;
        }
        return sum;
    }
}

