int main() {
    int n, count = 0, sum_of_squares = 0;
    scanf("%d", &n);
    int a[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
        // Check if the number is prime
        int is_prime = 1;
        if (a[i] < 2) is_prime = 0;
        for (int j = 2; j <= sqrt(a[i]); j++) {
            if (a[i] % j == 0) {
                is_prime = 0;
                break;
            }
        }
        if (is_prime) count++;
        sum_of_squares += a[i] * a[i];
    }
    int key = count ? sum_of_squares % count : 0;
    printf("%d
", key);
    return 0;
}

