#include <stdio.h>
int main() {
    int n;
    scanf("%d", &n);
    int scores[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &scores[i]);
    }
    int low = scores[0], high = scores[n - 1], threshold = -1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (scores[i] >= mid) count++;
        }
        if ((double)count / n > 0.7) {
            threshold = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    printf("%d
", threshold);
    return 0;
}

