#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int cmp(const void *a, const void *b) {
    const char *str1 = *(const char **)a;
    const char *str2 = *(const char **)b;
    int len1 = strlen(str1);
    int len2 = strlen(str2);
    if (len1 == len2) {
        return strcmp(str1, str2);
    }
    return len1 - len2;
}
int main() {
    int N;
    scanf("%d", &N);
    char **posts = (char **)malloc(N * sizeof(char *));
    int count = 0;
    char temp[101];
    for (int i = 0; i < N; i++) {
        scanf("%s", temp);
        int isDuplicate = 0;
        for (int j = 0; j < count; j++) {
            if (strcmp(posts[j], temp) == 0) {
                isDuplicate = 1;
                break;
            }
        }
        if (!isDuplicate) {
            posts[count] = (char *)malloc((strlen(temp) + 1) * sizeof(char));
            strcpy(posts[count], temp);
            count++;
        }
    }
    qsort(posts, count, sizeof(char *), cmp);
    for (int i = 0; i < count; i++) {
        printf("%s
", posts[i]);
        free(posts[i]);
    }
    free(posts);
    return 0;
}

