#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
int main() {
    int N;
    scanf("%d", &N);
    int **dependencies = (int **)malloc(N * sizeof(int *));
    int *dep_count = (int *)malloc(N * sizeof(int));
    bool *visited = (bool *)malloc(N * sizeof(bool));
    for (int i = 0; i < N; i++) {
        dep_count[i] = 0;
        visited[i] = false;
        int count;
        scanf("%d", &count);
        dependencies[i] = (int *)malloc(count * sizeof(int));
        for (int j = 0; j < count; j++) {
            scanf("%d", &dependencies[i][j]);
            dep_count[i]++;
        }
    }
    int visit_count = 0;
    void dfs(int package) {
        if (visited[package]) return;
        visited[package] = true;
        visit_count++;
        for (int i = 0; i < dep_count[package]; i++) {
            dfs(dependencies[package][i] - 1);
        }
    }
    dfs(0);
