    set<int> visited;
    stack<int> to_visit;
    to_visit.push(0); // Start from package 1 (index 0)
    while (!to_visit.empty()) {
        int current = to_visit.top();
        to_visit.pop();
        if (visited.find(current) == visited.end()) {
            visited.insert(current);
            for (int neighbor : dependencies[current]) {
                to_visit.push(neighbor);
            }
        }
    }
    cout << visited.size() << endl;
    return 0;
}

import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        List<List<Integer>> dependencies = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            List<Integer> dep = new ArrayList<>();
            while (true) {
                int depIndex = scanner.nextInt();
                if (depIndex == 0) break;
                dep.add(depIndex - 1);
            }
            dependencies.add(dep);
        }
        boolean[] visited = new boolean[N];
        int count = dfs(0, dependencies, visited);
        System.out.println(count);
    }
    private static int dfs(int packageIndex, List<List<Integer>> dependencies, boolean[] visited) {
        if (visited[packageIndex]) return 0;
        visited[packageIndex] = true;
        int total = 1; // Count this package
        for (int dep : dependencies.get(packageIndex)) {
            total += dfs(dep, dependencies, visited);
        }
        return total;
    }
}

