public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        int[] A = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = scanner.nextInt();
        }
        int firstSample = A[0];
        int lastSample = A[N - 1];
        int gcd = calculateGCD(firstSample, lastSample);
        System.out.println(gcd);
    }
    private static int calculateGCD(int a, int b) {
        while (b != 0) {
            int t = b;
            b = a % b;
            a = t;
        }
        return a;
    }
}

