#include <stdio.h>
#include <stdlib.h>
#define MAX 100
int queue[MAX][2], front = 0, rear = 0;
void enqueue(int x, int y) {
    queue[rear][0] = x;
    queue[rear][1] = y;
    rear++;
}
int dequeue(int *x, int *y) {
    if (front < rear) {
        *x = queue[front][0];
        *y = queue[front][1];
        front++;
        return 1;
    }
    return 0;
}
int is_empty() {
    return front == rear;
}
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int maze[MAX][MAX];
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            scanf("%d", &maze[i][j]);
        }
    }
    int directions[4][2] = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};
    int visited[MAX][MAX] = {0};
    int distance[MAX][MAX] = {0};
    if (maze[0][0] == 1 || maze[N-1][M-1] == 1) {
        printf("-1
");
        return 0;
    }
    enqueue(0, 0);
    visited[0][0] = 1;
    distance[0][0] = 1;
    while (!is_empty()) {
        int x, y;
        dequeue(&x, &y);
        for (int i = 0; i < 4; i++) {
            int new_x = x + directions[i][0];
            int new_y = y + directions[i][1];
            if (new_x >= 0 && new_x < N && new_y >= 0 && new_y < M && 
                maze[new_x][new_y] == 0 && !visited[new_x][new_y]) {
                visited[new_x][new_y] = 1;
                distance[new_x][new_y] = distance[x][y] + 1;
                enqueue(new_x, new_y);
                if (new_x == N-1 && new_y == M-1) {
                    printf("%d
", distance[new_x][new_y]);
                    return 0;
                }
            }
        }
    }
    printf("-1
");
    return 0;
}

