        for (int j = 0; j < M; ++j) {
            cin >> maze[i][j];
        }
    }
    // Directions for moving in the maze
    vector<pair<int, int>> directions = {{1, 0}, {0, 1}, {-1, 0}, {0, -1}};
    queue<pair<int, int>> q;
    vector<vector<bool>> visited(N, vector<bool>(M, false));
    q.push({0, 0});
