                int nx = x + dx;
                int ny = y + dy;
                if (nx >= 0 && ny >= 0 && nx < N && ny < M && maze[nx][ny] == 0 && !visited[nx][ny]) {
                    visited[nx][ny] = true;
                    q.push({nx, ny});
                }
            }
        }
        steps++;
    }
