import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int h = scanner.nextInt();
        int w = scanner.nextInt();
        int[][] image = new int[h][w];
        for (int i = 0; i < h; i++) {
            for (int j = 0; j < w; j++) {
                image[i][j] = scanner.nextInt();
            }
        }
        int x = scanner.nextInt();
        int y = scanner.nextInt();
        int newColor = scanner.nextInt();
        int originalColor = image[x][y];
        if (originalColor != newColor) {
            fill(image, x, y, originalColor, newColor);
        }
        for (int i = 0; i < h; i++) {
            for (int j = 0; j < w; j++) {
                System.out.print(image[i][j] + (j == w - 1 ? "
" : " "));
            }
        }
    }
    public static void fill(int[][] image, int x, int y, int originalColor, int newColor) {
        if (x < 0 || x >= image.length || y < 0 || y >= image[0].length) return;
        if (image[x][y] != originalColor) return;
        image[x][y] = newColor;
        fill(image, x + 1, y, originalColor, newColor);
        fill(image, x - 1, y, originalColor, newColor);
        fill(image, x, y + 1, originalColor, newColor);
        fill(image, x, y - 1, originalColor, newColor);
    }
}

