    int unique_count = 0;
    for (int i = 0; i < n; i++) {
        scanf("%s", codes[i]);
        for (int j = 0; j < strlen(codes[i]); j++) {
            codes[i][j] = tolower(codes[i][j]);
        }
    }
    for (int i = 0; i < n; i++) {
        int is_unique = 1;
        for (int j = 0; j < unique_count; j++) {
            if (strcmp(codes[i], unique[j]) == 0) {
                is_unique = 0;
                break;
            }
        }
        if (is_unique) {
            strcpy(unique[unique_count], codes[i]);
            unique_count++;
        }
    }
    // Sort the unique codes
    for (int i = 0; i < unique_count - 1; i++) {
        for (int j = i + 1; j < unique_count; j++) {
            if (strcmp(unique[i], unique[j]) > 0) {
                char temp[101];
                strcpy(temp, unique[i]);
                strcpy(unique[i], unique[j]);
                strcpy(unique[j], temp);
            }
        }
    }
    for (int i = 0; i < unique_count; i++) {
        printf("%s
", unique[i]);
