#include <stdio.h>
#include <string.h>
#include <stdlib.h>
typedef struct Item {
    char name[50];
    int stock;
    struct Item* next;
} Item;
typedef struct Category {
    char name[50];
    Item* items;
    struct Category* next;
} Category;
Category* categories = NULL;
void add_item(const char* category_name, const char* item_name, int stock) {
    Category* category = categories;
    while (category) {
        if (strcmp(category->name, category_name) == 0) {
            Item* item = category->items;
            while (item) {
                if (strcmp(item->name, item_name) == 0) {
                    item->stock += stock;
                    return;
                }
                item = item->next;
            }
            Item* new_item = (Item*)malloc(sizeof(Item));
            strcpy(new_item->name, item_name);
            new_item->stock = stock;
            new_item->next = category->items;
            category->items = new_item;
            return;
        }
        category = category->next;
    }
    Category* new_category = (Category*)malloc(sizeof(Category));
    strcpy(new_category->name, category_name);
    new_category->items = NULL;
    new_category->next = categories;
    categories = new_category;
    add_item(category_name, item_name, stock);
}
void remove_item(const char* category_name, const char* item_name) {
    Category* category = categories;
    while (category) {
        if (strcmp(category->name, category_name) == 0) {
            Item* item = category->items;
            Item* prev_item = NULL;
            while (item) {
                if (strcmp(item->name, item_name) == 0) {
                    if (item->stock > 0) {
                        item->stock--;
                    }
                    if (item->stock == 0) {
                        if (prev_item) {
                            prev_item->next = item->next;
                        } else {
                            category->items = item->next;
                        }
                        free(item);
                    }
                    return;
                }
                prev_item = item;
                item = item->next;
            }
            return;
        }
        category = category->next;
    }
}
void display_inventory() {
    Category* category = categories;
    while (category) {
        printf("%s: ", category->name);
        Item* item = category->items;
        while (item) {
            printf("%s (%d), ", item->name, item->stock);
            item = item->next;
        }
        printf("
");
        category = category->next;
    }
}
int main() {
    add_item("Fruits", "Apple", 10);
    add_item("Fruits", "Banana", 5);
    remove_item("Fruits", "Apple");
    add_item("Fruits", "Apple", 3);
    remove_item("Fruits", "Banana");
    add_item("Vegetables", "Carrot", 2);
    remove_item("Vegetables", "Carrot");
    display_inventory();
    return 0;
}

