import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
public class InventoryManagement {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        Map<String, Map<String, Integer>> inventory = new HashMap<>();
        while (scanner.hasNextLine()) {
            String line = scanner.nextLine();
            if (line.isEmpty()) break;
            String[] parts = line.split(" ");
            String action = parts[0];
            String category = parts[1];
            if (action.equals("add")) {
                String item = parts[2];
                int quantity = Integer.parseInt(parts[3]);
                inventory.putIfAbsent(category, new HashMap<>());
                inventory.get(category).put(item, inventory.get(category).getOrDefault(item, 0) + quantity);
            } else if (action.equals("remove")) {
                String item = parts[2];
                if (inventory.containsKey(category) && inventory.get(category).containsKey(item)) {
                    int currentStock = inventory.get(category).get(item);
                    if (currentStock <= 1) {
                        inventory.get(category).remove(item);
                    } else {
                        inventory.get(category).put(item, currentStock - 1);
                    }
                }
            }
        }
        for (String category : inventory.keySet()) {
            Map<String, Integer> items = inventory.get(category);
            StringBuilder output = new StringBuilder(category + ":");
            for (Map.Entry<String, Integer> entry : items.entrySet()) {
                output.append(String.format(" %s (%d),", entry.getKey(), entry.getValue()));
            }
            output.deleteCharAt(output.length() - 1); // Remove the trailing comma
