int main() {
    char command[100];
    while (1) {
        scanf("%s", command);
        if (strcmp(command, "add") == 0) {
            scanf("%s %s %s %d", places[place_count].name, places[place_count].date, places[place_count].purpose, &places[place_count].priority);
            printf("訪問候補地「%s」を追加しました。
", places[place_count].name);
            place_count++;
        } else if (strcmp(command, "update") == 0) {
            char name[100];
            scanf("%s %s %s %d", name, places[place_count].date, places[place_count].purpose, &places[place_count].priority);
            for (int i = 0; i < place_count; i++) {
                if (strcmp(places[i].name, name) == 0) {
                    strcpy(places[i].date, places[place_count].date);
                    strcpy(places[i].purpose, places[place_count].purpose);
                    places[i].priority = places[place_count].priority;
                    printf("訪問候補地「%s」の情報を更新しました。
