#include <iostream>
#include <map>
#include <string>
#include <sstream>
int main() {
    std::map<std::string, std::tuple<std::string, std::string, int>> places;
    std::string command;
    while (std::getline(std::cin, command)) {
        std::istringstream iss(command);
        std::string action;
        iss >> action;
        if (action == "add") {
            std::string name, date, purpose;
            int priority;
            iss >> name >> date >> purpose >> priority;
            places[name] = std::make_tuple(date, purpose, priority);
            std::cout << "訪問候補地「" << name << "」を追加しました。" << std::endl;
        } else if (action == "update") {
            std::string name, date, purpose;
            int priority;
            iss >> name >> date >> purpose >> priority;
            if (places.find(name) != places.end()) {
                places[name] = std::make_tuple(date, purpose, priority);
                std::cout << "訪問候補地「" << name << "」の情報を更新しました。" << std::endl;
            }
        } else if (action == "delete") {
            std::string name;
            iss >> name;
            if (places.erase(name) > 0) {
                std::cout << "訪問候補地「" << name << "」を削除しました。" << std::endl;
            }
        } else if (action == "list") {
            std::cout << "訪問候補地のリスト:" << std::endl;
            for (const auto& place : places) {
                std::cout << "- " << place.first << ": " << std::get<0>(place.second) << ", " << std::get<1>(place.second) << ", 優先度: " << std::get<2>(place.second) << std::endl;
            }
        }
    }
