public class TravelPlanner {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        Map<String, String[]> destinations = new HashMap<>();
        String command;
        while (true) {
            command = scanner.nextLine();
            String[] parts = command.split(" ");
            switch (parts[0]) {
                case "add":
                    destinations.put(parts[1], new String[]{parts[2], parts[3], parts[4]});
                    System.out.println("訪問候補地「" + parts[1] + "」を追加しました。");
                    break;
                case "update":
                    if (destinations.containsKey(parts[1])) {
                        destinations.put(parts[1], new String[]{parts[2], parts[3], parts[4]});
                        System.out.println("訪問候補地「" + parts[1] + "」の情報を更新しました。");
                    } else {
                        System.out.println("訪問候補地「" + parts[1] + "」は存在しません。");
                    }
                    break;
                case "delete":
                    if (destinations.remove(parts[1]) != null) {
                        System.out.println("訪問候補地「" + parts[1] + "」を削除しました。");
                    } else {
                        System.out.println("訪問候補地「" + parts[1] + "」は存在しません。");
                    }
                    break;
                case "list":
                    System.out.println("訪問候補地のリスト:");
                    for (Map.Entry<String, String[]> entry : destinations.entrySet()) {
                        System.out.println("- " + entry.getKey() + ": " + String.join(", ", entry.getValue()));
                    }
                    break;
                default:
                    System.out.println("無効なコマンドです。");
                    break;
            }
        }
    }
}

#include <stdio.h>
#include <stdlib.h>
void fill(int **image, int x, int y, int newColor, int originalColor, int m, int n) {
    if (x < 0 || x >= m || y < 0 || y >= n || image[x][y] != originalColor) {
        return;
    }
    image[x][y] = newColor;
    fill(image, x + 1, y, newColor, originalColor, m, n);
    fill(image, x - 1, y, newColor, originalColor, m, n);
    fill(image, x, y + 1, newColor, originalColor, m, n);
    fill(image, x, y - 1, newColor, originalColor, m, n);
}
int main() {
    int m, n;
    scanf("%d %d", &m, &n);
    int **image = (int **)malloc(m * sizeof(int *));
    for (int i = 0; i < m; i++) {
        image[i] = (int *)malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            scanf("%d", &image[i][j]);
        }
    }
    int x, y, newColor;
    scanf("%d %d %d", &x, &y, &newColor);
    fill(image, x, y, newColor, image[x][y], m, n);
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            printf("%d ", image[i][j]);
        }
        printf("
");
    }
    for (int i = 0; i < m; i++) {
        free(image[i]);
    }
    free(image);
    return 0;
}

#include <iostream>
#include <vector>
using namespace std;
void floodFill(vector<vector<int>>& image, int x, int y, int newColor, int originalColor) {
    if (x < 0 || x >= image.size() || y < 0 || y >= image[0].size()) return;
    if (image[x][y] != originalColor) return;
    image[x][y] = newColor;
    floodFill(image, x + 1, y, newColor, originalColor);
    floodFill(image, x - 1, y, newColor, originalColor);
    floodFill(image, x, y + 1, newColor, originalColor);
    floodFill(image, x, y - 1, newColor, originalColor);
}
int main() {
    int m, n;
    cin >> m >> n;
    vector<vector<int>> image(m, vector<int>(n));
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            cin >> image[i][j];
        }
    }
    int x, y, newColor;
    cin >> x >> y >> newColor;
    int originalColor = image[x][y];
    if (originalColor != newColor) {
        floodFill(image, x, y, newColor, originalColor);
    }
    for (const auto& row : image) {
        for (int color : row) {
            cout << color << " ";
        }
        cout << endl;
    }
    return 0;
}

import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int m = scanner.nextInt();
        int n = scanner.nextInt();
        int[][] image = new int[m][n];
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                image[i][j] = scanner.nextInt();
            }
        }
        int startX = scanner.nextInt();
        int startY = scanner.nextInt();
        int newColor = scanner.nextInt();
        int originalColor = image[startX][startY];
        if (originalColor != newColor) {
            floodFill(image, startX, startY, originalColor, newColor);
        }
        for (int[] row : image) {
            for (int pixel : row) {
                System.out.print(pixel + " ");
            }
            System.out.println();
        }
    }
    private static void floodFill(int[][] image, int x, int y, int originalColor, int newColor) {
        if (x < 0 || x >= image.length || y < 0 || y >= image[0].length || image[x][y] != originalColor) {
            return;
        }
        image[x][y] = newColor;
        floodFill(image, x + 1, y, originalColor, newColor);
        floodFill(image, x - 1, y, originalColor, newColor);
        floodFill(image, x, y + 1, originalColor, newColor);
        floodFill(image, x, y - 1, originalColor, newColor);
    }
}

