int package_count = 0;
void dfs(char *pkg_name, int visited[]) {
    for (int i = 0; i < package_count; i++) {
        if (strcmp(packages[i].name, pkg_name) == 0) {
            for (int j = 0; j < packages[i].dep_count; j++) {
                if (!visited[i]) {
                    visited[i] = 1;
                    printf("%s
", packages[i].dependencies[j]);
                    dfs(packages[i].dependencies[j], visited);
                }
            }
        }
    }
}
