import java.util.*;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = Integer.parseInt(scanner.nextLine());
        Map<String, List<String>> dependencies = new HashMap<>();
        Set<String> visited = new HashSet<>();
        for (int i = 0; i < n; i++) {
            String[] parts = scanner.nextLine().split(:);
            String packageName = parts[0];
            List<String> deps = Arrays.asList(parts[1].split(,"));
            dependencies.put(packageName, deps);
        }
        String targetPackage = scanner.nextLine();
        if (!dependencies.containsKey(targetPackage)) {
            System.out.println(指定されたパッケージは存在しません);
        } else {
            dfs(targetPackage, dependencies, visited);
        }
    }
    private static void dfs(String packageName, Map<String, List<String>> dependencies, Set<String> visited) {
        visited.add(packageName);
        for (String dep : dependencies.get(packageName)) {
            if (!visited.contains(dep)) {
                System.out.println(dep);
                dfs(dep, dependencies, visited);
            }
        }
    }
}

