#include <stdio.h>
#include <stdlib.h>
int gcd(int a, int b) {
    return b == 0 ? a : gcd(b, a % b);
}
int lcm(int a, int b) {
    return (a * b) / gcd(a, b);
}
int main() {
    int n;
    scanf("%d", &n);
    int *gears = (int *)malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &gears[i]);
    }
    // Selection sort
    for (int i = 0; i < n - 1; i++) {
        int min_index = i;
        for (int j = i + 1; j < n; j++) {
            if (gears[j] < gears[min_index]) {
                min_index = j;
            }
        }
        int temp = gears[i];
        gears[i] = gears[min_index];
        gears[min_index] = temp;
    }
    // Calculate LCM
    int result_lcm = gears[0];
    for (int i = 1; i < n; i++) {
        result_lcm = lcm(result_lcm, gears[i]);
    }
    // Output sorted gears
    for (int i = 0; i < n; i++) {
        printf("%d ", gears[i]);
    }
    printf("
%d
", result_lcm);
    free(gears);
    return 0;
}

