import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int[] gears = new int[n];
        for (int i = 0; i < n; i++) {
            gears[i] = scanner.nextInt();
        }
        // Selection Sort
        for (int i = 0; i < n - 1; i++) {
            int minIndex = i;
            for (int j = i + 1; j < n; j++) {
                if (gears[j] < gears[minIndex]) {
                    minIndex = j;
                }
            }
            int temp = gears[i];
            gears[i] = gears[minIndex];
            gears[minIndex] = temp;
        }
        // Calculate LCM
        int lcm = gears[0];
        for (int i = 1; i < n; i++) {
            lcm = (lcm * gears[i]) / gcd(lcm, gears[i]);
        }
        // Output
        for (int i = 0; i < n; i++) {
            System.out.print(gears[i] + " ");
        }
        System.out.println();
        System.out.println(lcm);
    }
    private static int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }
}

