#include <stdio.h>
#include <stdlib.h>
#include <string.h>
typedef struct {
    char name[100];
    int score;
} Team;
int compare(const void *a, const void *b) {
    Team *teamA = (Team *)a;
    Team *teamB = (Team *)b;
    if (teamB->score != teamA->score) {
        return teamB->score - teamA->score;
    }
    return strcmp(teamA->name, teamB->name);
}
int main() {
    int N;
    scanf("%d", &N);
    Team teams[100];
    for (int i = 0; i < N; i++) {
        scanf("%s %d", teams[i].name, &teams[i].score);
    }
    qsort(teams, N, sizeof(Team), compare);
    for (int i = 0; i < N; i++) {
        printf("%d %s %d
", i + 1, teams[i].name, teams[i].score);
    }
    return 0;
}

