#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main() {
    char *initial_places = malloc(100);
    char *add_places = malloc(100);
    char *remove_places = malloc(100);
    fgets(initial_places, 100, stdin);
    fgets(add_places, 100, stdin);
    fgets(remove_places, 100, stdin);
    // Remove newline characters
    initial_places[strcspn(initial_places, "
")] = 0;
    add_places[strcspn(add_places, "
")] = 0;
    remove_places[strcspn(remove_places, "
")] = 0;
    // Create a list of places
    char *places[100];
    int count = 0;
    // Initial places
    char *token = strtok(initial_places, ",");
    while (token != NULL) {
        places[count++] = strdup(token);
        token = strtok(NULL, ",");
    }
    // Add places
    token = strtok(add_places, ",");
    while (token != NULL) {
        places[count++] = strdup(token);
        token = strtok(NULL, ",");
    }
    // Remove places
    char *remove_token = strtok(remove_places, ",");
    while (remove_token != NULL) {
        for (int i = 0; i < count; i++) {
            if (strcmp(places[i], remove_token) == 0) {
                free(places[i]);
                places[i] = places[count - 1];
                count--;
                i--;
            }
        }
        remove_token = strtok(NULL, ",");
    }
    // Sort places
    for (int i = 0; i < count - 1; i++) {
        for (int j = i + 1; j < count; j++) {
            if (strcmp(places[i], places[j]) > 0) {
                char *temp = places[i];
                places[i] = places[j];
                places[j] = temp;
            }
        }
    }
    // Print sorted places
    for (int i = 0; i < count; i++) {
        printf("%s", places[i]);
        if (i < count - 1) {
            printf(",");
