#include <stdio.h>
#include <stdlib.h>
int main() {
    int N;
    scanf("%d", &N);
    int scores[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &scores[i]);
    }
    int *sorted_scores = (int *)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        sorted_scores[i] = scores[i];
    }
    // Sort the scores
    for (int i = 0; i < N - 1; i++) {
        for (int j = i + 1; j < N; j++) {
            if (sorted_scores[i] > sorted_scores[j]) {
                int temp = sorted_scores[i];
                sorted_scores[i] = sorted_scores[j];
                sorted_scores[j] = temp;
            }
        }
    }
    int ranks[N];
    for (int i = 0; i < N; i++) {
        ranks[i] = 1;
        for (int j = 0; j < N; j++) {
            if (sorted_scores[i] > sorted_scores[j]) {
                ranks[i]++;
            }
        }
    }
    // Adjust ranks for ties
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            if (sorted_scores[i] == sorted_scores[j]) {
                ranks[j] = ranks[i];
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", ranks[i]);
    }
    free(sorted_scores);
    return 0;
}

