    vector<string> top_titles;
    map<int, vector<string>> rank_map;
    for (int i = 0; i < N; ++i) {
        if (i == 0 || videos[i].first != videos[i - 1].first) {
            if (top_titles.size() < N) top_titles.push_back(videos[i].second);
        }
        rank_map[videos[i].first].push_back(videos[i].second);
    }
    // Output top N titles
    for (const string& title : top_titles) {
        cout << title << endl;
    }
    // Output all titles sorted by views
    for (const auto& entry : rank_map) {
        for (const string& title : entry.second) {
            cout << title << endl;
        }
    }
    return 0;
}

