        count++;
        if (temperatures[i] > max_temp) max_temp = temperatures[i];
        if (temperatures[i] < min_temp) min_temp = temperatures[i];
    }
    double avg_period = sum / count;
    // 2. Calculate the difference between max and min temperature
    int temp_diff = max_temp - min_temp;
    // 3. Calculate average temperature of the reversed array
    std::reverse(temperatures.begin(), temperatures.end());
    sum = 0;
    for (int temp : temperatures) {
        sum += temp;
    }
    double avg_reversed = sum / temperatures.size();
    // Output results
    std::cout << std::fixed << std::setprecision(2) << avg_period << std::endl;
    std::cout << temp_diff << std::endl;
    std::cout << std::fixed << std::setprecision(2) << avg_reversed << std::endl;
