typedef struct {
    char name[100];
    int votes;
} Candidate;
int compare(const void *a, const void *b) {
    Candidate *c1 = (Candidate *)a;
    Candidate *c2 = (Candidate *)b;
    if (c1->votes != c2->votes) {
        return c2->votes - c1->votes;
    }
    return strcmp(c1->name, c2->name);
}
int main() {
    int M, N;
    scanf("%d %d", &M, &N);
    Candidate candidates[100];
    int count = 0;
    for (int i = 0; i < M; i++) {
        char name[100];
        int votes;
        scanf("%s %d", name, &votes);
        int found = 0;
        for (int j = 0; j < count; j++) {
            if (strcmp(candidates[j].name, name) == 0) {
                candidates[j].votes += votes;
                found = 1;
                break;
            }
        }
        if (!found) {
            strcpy(candidates[count].name, name);
            candidates[count].votes = votes;
            count++;
        }
    }
    qsort(candidates, count, sizeof(Candidate), compare);
    for (int i = 0; i < N; i++) {
        printf("%s %d
", candidates[i].name, candidates[i].votes);
    }
    return 0;
}

