        if (prices[i] != prices[i - 1]) {
            unique_prices[j++] = prices[i];
        }
    }
    // 二分探索
    int left = 0, right = unique_count - 1;
    int result = -1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (unique_prices[mid] >= k) {
            result = unique_prices[mid];
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    printf("%d
", result);
    free(prices);
    free(unique_prices);
    return 0;
}

