from typing import List, Tuple
def text_editor(operations: List[Tuple[str, str]]) -> str:
    text = ''
    history = []
    for operation, value in operations:
        if operation == 'add':
            history.append(text)
            text += value
        elif operation == 'remove':
            if text:
                history.append(text)
                text = text[:-1]
        elif operation == 'undo':
            if history:
                text = history.pop()
    return text

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX_OPERATIONS 1000
typedef struct {
    char **history;
    int size;
    int capacity;
} TextEditor;
TextEditor* create_editor() {
    TextEditor *editor = (TextEditor*)malloc(sizeof(TextEditor));
    editor->history = (char**)malloc(sizeof(char*) * MAX_OPERATIONS);
    editor->size = 0;
    editor->capacity = MAX_OPERATIONS;
    return editor;
}
void add(TextEditor *editor, const char *text) {
    editor->history[editor->size++] = strdup(text);
}
void remove_last(TextEditor *editor) {
    if (editor->size > 0) {
        free(editor->history[--editor->size]);
    }
}
void undo(TextEditor *editor) {
    if (editor->size > 0) {
        free(editor->history[--editor->size]);
    }
}
char* text_editor(char operations[][2][100], int n) {
    TextEditor *editor = create_editor();
    char *final_text = (char*)malloc(sizeof(char) * 10000);
    final_text[0] = '\0';
    for (int i = 0; i < n; i++) {
        if (strcmp(operations[i][0], "add") == 0) {
            add(editor, operations[i][1]);
        } else if (strcmp(operations[i][0], "remove") == 0) {
            remove_last(editor);
        } else if (strcmp(operations[i][0], "undo") == 0) {
            undo(editor);
        }
    }
    for (int i = 0; i < editor->size; i++) {
        strcat(final_text, editor->history[i]);
        free(editor->history[i]);
    }
    free(editor->history);
    free(editor);
    return final_text;
}
int main() {
    char operations[5][2][100] = {
        {"add", "Hello"},
        {"add", " World"},
        {"remove", ""},
        {"undo", ""},
        {"add", "!"}
    };
    char *result = text_editor(operations, 5);
    printf("%s
", result);
    free(result);
    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <stack>
std::string text_editor(const std::vector<std::pair<std::string, std::string>>& operations) {
    std::string current_text;
    std::stack<std::string> history;
    for (const auto& operation : operations) {
        if (operation.first == "add") {
            history.push(current_text);
            current_text += operation.second;
        } else if (operation.first == "remove") {
            if (!current_text.empty()) {
                history.push(current_text);
                current_text.pop_back();
            }
        } else if (operation.first == "undo") {
            if (!history.empty()) {
                current_text = history.top();
                history.pop();
            }
        }
    }
    return current_text;
}
int main() {
    std::vector<std::pair<std::string, std::string>> operations = {{"add", "Hello"}, {"add", " World"}, {"remove", ""}, {"undo", ""}, {"add", "!"}};
    std::cout << text_editor(operations) << std::endl;
    return 0;
}

import java.util.ArrayList;
