import java.util.ArrayList;
import java.util.Collections;
import java.util.Comparator;
import java.util.List;
class ScheduleManager {
    static class Schedule {
        String appliance;
        String startTime;
        String endTime;
        Schedule(String appliance, String startTime, String endTime) {
            this.appliance = appliance;
            this.startTime = startTime;
            this.endTime = endTime;
        }
    }
    private List<Schedule> schedules = new ArrayList<>();
    public List<Schedule> addSchedule(String appliance, String startTime, String endTime) {
        boolean updated = false;
        for (int i = 0; i < schedules.size(); i++) {
            Schedule existing = schedules.get(i);
            if ((startTime.compareTo(existing.endTime) < 0 && endTime.compareTo(existing.startTime) > 0)) {
                schedules.set(i, new Schedule(appliance, startTime, endTime));
                updated = true;
                break;
            }
        }
        if (!updated) {
            schedules.add(new Schedule(appliance, startTime, endTime));
        }
        Collections.sort(schedules, Comparator.comparing(s -> s.startTime));
        return schedules;
    }
    public void printSchedules() {
        for (Schedule schedule : schedules) {
            System.out.println(schedule.appliance + " " + schedule.startTime + " " + schedule.endTime);
        }
    }
}
public class Main {
    public static void main(String[] args) {
        ScheduleManager manager = new ScheduleManager();
        manager.addSchedule("エアコン", "09:00", "10:00");
        manager.addSchedule("掃除機", "10:30", "11:30");
        manager.addSchedule("エアコン", "10:00", "11:00");
