import java.util.*;
public class PrintManager {
    public static Tuple<List<String>, Integer> managePrintJobs(Object... jobs) {
        int speed = 1;
        List<Tuple<String, Integer>> jobList = new ArrayList<>();
        for (Object job : jobs) {
            if (job instanceof Tuple) {
                jobList.add((Tuple<String, Integer>) job);
            } else if (job instanceof Integer) {
                speed = (Integer) job;
            }
        }
        if (jobList.isEmpty()) {
            return new Tuple<>(Collections.singletonList("印刷要求がありません"), 0);
        }
        // Sort jobs by priority (higher number means higher priority)
        jobList.sort((a, b) -> b.y - a.y);
        List<String> printedJobs = new ArrayList<>();
        int totalTime = 0;
        for (Tuple<String, Integer> job : jobList) {
            printedJobs.add(job.x);
            totalTime += job.y * speed;
        }
        return new Tuple<>(printedJobs, totalTime);
    }
    public static class Tuple<X, Y> {
        public final X x;
        public final Y y;
        public Tuple(X x, Y y) {
            this.x = x;
            this.y = y;
        }
    }
}

