class TaskManager:
    def __init__(self):
        self.tasks = {}
    def update_progress(self, name: str, task: str, status: str):
        if name not in self.tasks:
            self.tasks[name] = []
        if status == '完了':
            if task in self.tasks[name]:
                self.tasks[name].remove(task)
        else:
            if task not in self.tasks[name]:
                self.tasks[name].append(task)
        return self.tasks
    def swap_tasks(self, name1: str, name2: str):
        if name1 not in self.tasks or name2 not in self.tasks:
            return 'エラー: 担当者が存在しません。'
        self.tasks[name1], self.tasks[name2] = self.tasks[name2], self.tasks[name1]
        return self.tasks
    def get_all_tasks(self, *names):
        result = {}
        for name in names:
            result[name] = self.tasks.get(name)
        return result
