#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#define MAX_TASKS 100
#define MAX_NAME_LEN 50
typedef struct {
    char name[MAX_NAME_LEN];
    char tasks[MAX_TASKS][MAX_NAME_LEN];
    int task_count;
} Person;
Person people[10];
int person_count = 0;
void add_person(const char *name) {
    strcpy(people[person_count].name, name);
    people[person_count].task_count = 0;
    person_count++;
}
int find_person(const char *name) {
    for (int i = 0; i < person_count; i++) {
        if (strcmp(people[i].name, name) == 0) {
            return i;
        }
    }
    return -1;
}
char* update_progress(const char *name, const char *task, const char *status) {
    int index = find_person(name);
    if (index == -1) return "";
    if (strcmp(status, "完了") == 0) {
        for (int i = 0; i < people[index].task_count; i++) {
            if (strcmp(people[index].tasks[i], task) == 0) {
                for (int j = i; j < people[index].task_count - 1; j++) {
                    strcpy(people[index].tasks[j], people[index].tasks[j + 1]);
                }
                people[index].task_count--;
                break;
            }
        }
    } else {
        strcpy(people[index].tasks[people[index].task_count++], task);
    }
    static char result[1024];
    sprintf(result, "{'%s': [", people[index].name);
    for (int i = 0; i < people[index].task_count; i++) {
        strcat(result, "'");
        strcat(result, people[index].tasks[i]);
        strcat(result, "'");
        if (i < people[index].task_count - 1) strcat(result, ", ");
    }
    strcat(result, "]}");
    return result;
}
char* swap_tasks(const char *name1, const char *name2) {
    int index1 = find_person(name1);
    int index2 = find_person(name2);
    if (index1 == -1 || index2 == -1) return "";
    char temp[MAX_TASKS][MAX_NAME_LEN];
    int temp_count = 0;
    for (int i = 0; i < people[index1].task_count; i++) {
        strcpy(temp[temp_count++], people[index1].tasks[i]);
    }
    for (int i = 0; i < people[index2].task_count; i++) {
        strcpy(people[index1].tasks[i], people[index2].tasks[i]);
    }
    people[index1].task_count = people[index2].task_count;
    for (int i = 0; i < temp_count; i++) {
        strcpy(people[index2].tasks[i], temp[i]);
    }
    people[index2].task_count = temp_count;
    static char result[2048];
    sprintf(result, "{'%s': [", people[index1].name);
    for (int i = 0; i < people[index1].task_count; i++) {
        strcat(result, "'");
        strcat(result, people[index1].tasks[i]);
        strcat(result, "'");
        if (i < people[index1].task_count - 1) strcat(result, ", ");
    }
    strcat(result, "], '%s': [", people[index2].name);
    for (int i = 0; i < people[index2].task_count; i++) {
        strcat(result, "'");
        strcat(result, people[index2].tasks[i]);
        strcat(result, "'");
        if (i < people[index2].task_count - 1) strcat(result, ", ");
    }
    strcat(result, "]}");
    return result;
}
char* get_all_tasks(int count, const char *names[]) {
    static char result[2048];
    strcpy(result, "{");
    for (int j = 0; j < count; j++) {
        int index = find_person(names[j]);
        if (index == -1) continue;
        sprintf(result + strlen(result), "'%s': [", people[index].name);
        for (int i = 0; i < people[index].task_count; i++) {
            strcat(result, "'");
            strcat(result, people[index].tasks[i]);
            strcat(result, "'");
            if (i < people[index].task_count - 1) strcat(result, ", ");
        }
        strcat(result, "]");
        if (j < count - 1) strcat(result, ", ");
    }
    strcat(result, "}");
    return result;
}
