    private Map<String, List<String>> tasks = new HashMap<>();
    public Map<String, List<String>> update_progress(String name, String task, String status) {
        tasks.putIfAbsent(name, new ArrayList<>());
        if (status.equals("完了")) {
            tasks.get(name).remove(task);
        } else {
            tasks.get(name).add(task);
        }
        return tasks;
    }
    public Map<String, List<String>> swap_tasks(String name1, String name2) {
        if (!tasks.containsKey(name1) || !tasks.containsKey(name2)) {
            throw new IllegalArgumentException("One or both names do not exist.");
        }
        List<String> temp = new ArrayList<>(tasks.get(name1));
        tasks.put(name1, new ArrayList<>(tasks.get(name2)));
        tasks.put(name2, temp);
        return tasks;
    }
    public Map<String, List<String>> get_all_tasks(String... names) {
        Map<String, List<String>> result = new HashMap<>();
        for (String name : names) {
            if (tasks.containsKey(name)) {
                result.put(name, tasks.get(name));
            }
        }
        return result;
    }
}

def bubble_sort_reviews(reviews):
    n = len(reviews)
    steps = []
    for i in range(n):
        for j in range(0, n-i-1):
            if reviews[j][0] < reviews[j+1][0]:
                reviews[j], reviews[j+1] = reviews[j+1], reviews[j]
        steps.append(reviews[:])
    return steps
