#include <string.h>
void bubble_sort_reviews(int reviews[][2], int n) {
    int i, j, temp; 
    for (i = 0; i < n-1; i++) {
        for (j = 0; j < n-i-1; j++) {
            if (reviews[j][0] < reviews[j+1][0]) {
                // Swap the reviews
                temp = reviews[j][0];
                reviews[j][0] = reviews[j+1][0];
                reviews[j+1][0] = temp;
                temp = reviews[j][1];
                reviews[j][1] = reviews[j+1][1];
                reviews[j+1][1] = temp;
            }
        }
        // Print the current state of reviews
        printf("[");
        for (int k = 0; k < n; k++) {
            printf("(%d, '%s')%s", reviews[k][0], reviews[k][1], (k < n-1) ? ", " : "");
        }
        printf("]
");
    }
}
