using namespace std;
vector<vector<pair<int, string>>> bubbleSortReviews(vector<pair<int, string>>& reviews) {
    vector<vector<pair<int, string>>> steps;
    int n = reviews.size();
    steps.push_back(reviews);
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (reviews[j].first < reviews[j + 1].first) {
                swap(reviews[j], reviews[j + 1]);
            }
        }
        steps.push_back(reviews);
    }
    return steps;
}
