}

import java.util.ArrayList;
import java.util.List;
public class ReviewSorter {
    public static List<List<Tuple>> bubbleSortReviews(List<Tuple> reviews) {
        List<List<Tuple>> steps = new ArrayList<>();
        int n = reviews.size();
        boolean swapped;
        do {
            swapped = false;
            for (int i = 0; i < n - 1; i++) {
                if (reviews.get(i).rating < reviews.get(i + 1).rating) {
                    Tuple temp = reviews.get(i);
                    reviews.set(i, reviews.get(i + 1));
                    reviews.set(i + 1, temp);
                    swapped = true;
                }
            }
            steps.add(new ArrayList<>(reviews));
        } while (swapped);
        return steps;
    }
    static class Tuple {
        int rating;
        String review;
        Tuple(int rating, String review) {
            this.rating = rating;
            this.review = review;
        }
    }
}

def find_min_price(prices, target):
    left, right = 0, len(prices) - 1
    result = None
    while left <= right:
        mid = (left + right) // 2
        if prices[mid] < target:
            left = mid + 1
        else:
            result = prices[mid]
            right = mid - 1
    return result

#include <stdio.h>
#include <stdlib.h>
int find_min_price(int prices[], int size, int target) {
    int left = 0, right = size - 1;
    int result = -1;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (prices[mid] >= target) {
            result = prices[mid];
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    return result == -1 ? -1 : result;
}
