def analyze_temperatures(temperatures, remove_outliers=True):
    if not temperatures:
        return 'Error: No temperature data provided.'
    if remove_outliers:
        mean_temp = sum(temperatures) / len(temperatures)
        filtered_temps = [temp for temp in temperatures if mean_temp - 10 <= temp <= mean_temp + 10]
        if not filtered_temps:
            return 'Error: No valid temperature data after outlier removal.'
    else:
        filtered_temps = temperatures
    return (sum(filtered_temps) / len(filtered_temps), max(filtered_temps), min(filtered_temps))

#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
typedef struct {
    float average;
    int max;
    int min;
} TemperatureStats;
TemperatureStats analyze_temperatures(int temperatures[], int size, bool remove_outliers) {
    if (size == 0) {
        printf("Error: No temperature data available.
");
        exit(1);
    }
    int min = temperatures[0];
    int max = temperatures[0];
    float sum = 0;
    int count = 0;
    float valid_min = remove_outliers ? (temperatures[0] - 10) : -101;
    float valid_max = remove_outliers ? (temperatures[0] + 10) : 101;
    for (int i = 0; i < size; i++) {
        if (!remove_outliers || (temperatures[i] >= valid_min && temperatures[i] <= valid_max)) {
            if (temperatures[i] < min) min = temperatures[i];
            if (temperatures[i] > max) max = temperatures[i];
            sum += temperatures[i];
            count++;
        }
    }
    TemperatureStats stats;
    stats.average = sum / count;
    stats.max = max;
    stats.min = min;
    return stats;
}
int main() {
    int temps1[] = {15, 20, 25, 30, 18, 100};
    TemperatureStats result1 = analyze_temperatures(temps1, 6, false);
    printf("(%.1f, %d, %d)
", result1.average, result1.max, result1.min);
    int temps2[] = {10, 12, 14, 11, 13};
    TemperatureStats result2 = analyze_temperatures(temps2, 5, true);
    printf("(%.1f, %d, %d)
", result2.average, result2.max, result2.min);
    return 0;
}

#include <iostream>
#include <vector>
#include <tuple>
#include <algorithm>
#include <stdexcept>
std::tuple<double, int, int> analyzeTemperatures(const std::vector<int>& temperatures, bool remove_outliers = true) {
    if (temperatures.empty()) {
        throw std::invalid_argument("Error: The list is empty.");
    }

    std::vector<int> valid_temperatures = temperatures;

    if (remove_outliers) {
        int min_temp = *std::min_element(temperatures.begin(), temperatures.end());
        int max_temp = *std::max_element(temperatures.begin(), temperatures.end());
        valid_temperatures.erase(std::remove_if(valid_temperatures.begin(), valid_temperatures.end(), 
            [min_temp, max_temp](int temp) {
                return temp < min_temp - 10 || temp > max_temp + 10;
            }), valid_temperatures.end());
    }

    double average = std::accumulate(valid_temperatures.begin(), valid_temperatures.end(), 0.0) / valid_temperatures.size();
    int max_temp = *std::max_element(valid_temperatures.begin(), valid_temperatures.end());
    int min_temp = *std::min_element(valid_temperatures.begin(), valid_temperatures.end());

    return std::make_tuple(average, max_temp, min_temp);
}
int main() {
    // Sample test
    auto result = analyzeTemperatures({15, 20, 25, 30, 18, 100}, false);
    std::cout << "Result: (" << std::get<0>(result) << ", " << std::get<1>(result) << ", " << std::get<2>(result) << ")" << std::endl;
    return 0;
}

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
public class TemperatureAnalysis {
    public static Object analyzeTemperatures(List<Integer> temperatures, boolean removeOutliers) {
        if (temperatures.isEmpty()) {
            return "Error: The list is empty.";
        }
        List<Integer> validTemperatures = new ArrayList<>(temperatures);
        if (removeOutliers) {
            int average = (int) validTemperatures.stream().mapToInt(Integer::intValue).average().orElse(0);
            validTemperatures.removeIf(temp -> temp < average - 10 || temp > average + 10);
        }
        double avg = validTemperatures.stream().mapToInt(Integer::intValue).average().orElse(0);
        int max = Collections.max(validTemperatures);
        int min = Collections.min(validTemperatures);
        return new double[]{avg, max, min};
    }
    public static void main(String[] args) {
        List<Integer> temperatures = List.of(15, 20, 25, 30, 18, 100);
        Object result = analyzeTemperatures(temperatures, false);
        System.out.println(result);
    }
}

