import java.util.*;
class RareBook implements Comparable<RareBook> {
    String title;
    int rarity;
    RareBook(String title, int rarity) {
        this.title = title;
        this.rarity = rarity;
    }
    @Override
    public int compareTo(RareBook other) {
        return Integer.compare(this.rarity, other.rarity);
    }
}
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        scanner.nextLine(); // consume the remaining newline
        List<RareBook> books = new ArrayList<>();
        for (int i = 0; i < N; i++) {
            String line = scanner.nextLine();
            String[] parts = line.split(" ");
            String title = parts[0];
            int rarity = Integer.parseInt(parts[1]);
            books.add(new RareBook(title, rarity));
        }
        String order = scanner.nextLine();
        if (order.equals("desc")) {
            Collections.sort(books, Collections.reverseOrder());
        } else {
            Collections.sort(books);
        }
        for (RareBook book : books) {
            System.out.println(book.title + ": " + book.rarity);
        }
    }
}
